namespace IstanbulAnkaraNakliyat.Models;

public static class IstanbulIlceDetaylar
{
    public static string GetIlceDetay(string slug) =>
        IlceDetaylar.TryGetValue(slug, out var d) ? d : "";

    public static string GetServisDetay(string slug, ServisTipi servis) =>
        ServisDetaylar.TryGetValue((slug, servis), out var d) ? d : "";

    private static readonly Dictionary<string, string> IlceDetaylar = new()
    {
        // ── GRUP 1: Anadolu Yakası Ana İlçeler ──
        ["kadikoy"]    = "Kadıköy, Moda'nın butik sokakları, Fikirtepe'nin kentsel dönüşüm yapıları ve Bostancı'nın sahil hattıyla birbirinden farklı yapı dokularını barındıran Anadolu yakasının en merkezi ilçesidir. Fikirtepe ve Göztepe'deki yeni konut projelerinde asansör koordinasyonu standarttır; Moda ve Kalamış'taki tarihi apartmanlarda kat başına taşıma süresi önceden hesaplanmaktadır. E-5 ve D-100 bağlantısıyla TEM girişine Ümraniye aksından 15–20 dakikada ulaşılmaktadır. Sabah 07:00 öncesi başlayan yüklemeler, köprü trafiğine yakalanmadan Ankara güzergâhına rahatça girmektedir.",
        ["uskudar"]    = "Üsküdar, Çengelköy, Kandilli, Kuzguncuk ve Beylerbeyi gibi Boğaz kıyısına yerleşmiş tarihi mahallelerinde yalı ve köşk dokusunu barındıran, kendine özgü bir lojistik yapısına sahip ilçedir. Bu tarihi bölgelerde büyük kamyon erişimi dar sokaklar nedeniyle kısıtlı olduğundan 3,5 ton kamyonetimiz standart çözüm olarak kullanılmakta; gerektiğinde ikincil araç transferiyle hizmet tamamlanmaktadır. Selimiye ve Altunizade'deki modern rezidans projelerinde ise geniş bina girişleri büyük mobilyaların sorunsuz taşınmasına imkân tanımaktadır. TEM bağlantısı Kadıköy–Ümraniye aksından sağlanmakta olup sabah erken çıkış tercih edilmektedir.",
        ["umraniye"]   = "Ümraniye, TEM E-5 güzergâhına en yakın Anadolu yakası ilçelerinden biri olup şehirlerarası taşımalarda coğrafi avantaj sağlamaktadır. Armağanevler, Siteler ve İnkılap mahallelerindeki planlı konut blokları geniş bina girişleri ve modern asansörler barındırmakta; yükleme operasyonları verimli biçimde planlanabilmektedir. İlçe genelinde hız kazanan kentsel dönüşüm, eski ve yeni yapılarda farklı lojistik deneyimi gerektirmektedir. TEM girişine 5–10 dakikada ulaşılabilmesi, Ankara taşımalarında gecikme riskini minimize etmektedir.",
        ["maltepe"]    = "Maltepe, Küçükyalı'nın sahil hattından Altayçeşme'nin platolarına uzanan karma bir konut ve ticaret ilçesidir. E-5 üzerinde yer alan ilçede Ankara güzergâhına doğrudan bağlantı sağlanmaktadır; Bağlarbaşı ve Cevizli'deki yüksek katlı yapılarda asansör koordinasyonu ile yükleme süreleri optimize edilmektedir. Küçükyalı sahil kesimindeki dar ve tek yönlü sokaklar için 3,5 ton kamyonet tercih edilmekte; platform yüksekliğine göre yükleme noktası önceden belirlenmektedir. Gülensu ve Altayçeşme mahallelerinde geniş anayollar kamyon erişimine de elverişlidir.",
        ["pendik"]     = "Pendik, Kurtköy'ün büyük konut sitelerinden Yenişehir'in ticaret bölgelerine, sahil şeridinden Sabiha Gökçen Havalimanı yakınlığına kadar geniş bir yapı çeşitliliğine sahip Anadolu yakası ilçesidir. Dolayoba ve Kaynarca'daki sitelerde geniş araç erişim yolları kamyon ve büyük araçlar için uygundur; Kurtköy'ün TEM bağlantısı şehirlerarası yüklemelerde zaman avantajı sağlamaktadır. Özellikle Şeyhli ve Yenişehir'deki yeni konut projelerinde asansörlü yapı oranı yüksektir. Sabiha Gökçen yakınlığı, uçuşla gelen ekip veya ekipman koordinasyonunu da kolaylaştırmaktadır.",
        ["kartal"]     = "Kartal, Soğanlık'ın yoğun konut dokusundan Yakacık'ın daha sakin yapısına uzanan, sanayi altyapısına alışkın bir Anadolu yakası ilçesidir. E-5 ve D-100'a doğrudan cephesi bulunan ilçede büyük araç geçişleri yaygındır; sanayi bölgelerinden kaynaklanan nakliyat talebi ekibi deneyimli kılmaktadır. Karlıktepe ve Uğur Mumcu'nun bazı iç sokaklarında kamyonet kullanımı önerilmekte; ana arterlere yakın adreslerde ise kamyon erişimi sorunsuz sağlanmaktadır. TEM Kurtköy güzergâhından 15–20 dakikada Ankara yoluna girilmektedir.",
        ["atasehir"]   = "Ataşehir, İstanbul'un yükselen finans ve yaşam merkezi olup İçerenköy'ün iş kuleleri, Küçükbakkalköy'ün rezidans siteleri ve Ferhatpaşa'nın gelişen konut bölgeleriyle yüksek değerli taşımaları sıklıkla barındırmaktadır. Modern yapı stoğunun egemen olduğu ilçede asansörlü binalarda yükleme operasyonları verimli planlanabilmekte; geniş bina girişleri büyük mobilyaların hasarsız taşınmasına imkân tanımaktadır. Kurumsal iş merkezi yoğunluğu nedeniyle hafta sonu ve gece ofis taşımaları ilçede sıkça tercih edilmektedir. E-5 ve TEM'e Ümraniye üzerinden erişim, Ataşehir'den Ankara güzergâhını kısaltmaktadır.",
        ["beykoz"]     = "Beykoz, Çubuklu ve Paşabahçe'nin Boğaz kıyı mahalleleri ile Riva ve Polonezköy'ün kırsal kesimlerinden oluşan, dar ve kıvrımlı yollara sahip doğal bir İstanbul ilçesidir. Büyük kamyon erişimi bazı köy ve çıkmaz sokaklarda kısıtlı olduğundan 3,5 ton kamyonet standart araç olarak kullanılmakta; gerektiğinde ikincil taşıma ile kombine çözüm üretilmektedir. İlçe merkezinden TEM'e Ümraniye ve Çekmeköy aksından ulaşılmaktadır; sabah erken çıkış Boğaz güzergâhındaki trafik sıkışıklığını aşmayı sağlamaktadır. Riva ve Polonezköy gibi uzak noktalarda adres bazlı güzergâh değerlendirmesi yapılmaktadır.",
        ["cekmekoy"]   = "Çekmeköy, Nişantepe, Taşdelen ve Hamidiye gibi yeşil ve sakin mahallelerinde müstakil ev, köşk ve küçük site taşımalarına sıkça ev sahipliği yapmaktadır. İlçedeki bazı villa ve müstakil konut bölgelerinde yol genişliği büyük araç erişimini güçleştirebileceğinden adres bazlı değerlendirme yapılmaktadır. Mehmet Akif ve Çekmeköy Merkez'deki apartman bloklarında asansör koordinasyonu standarttır. TEM'e Ümraniye–Çekmeköy güzergâhından ulaşılmakta olup sabah çıkışında yoğunluk kavşak geçildikten sonra hızla azalmaktadır.",

        // ── GRUP 2: Anadolu Yakası Doğu + Avrupa Yakası Prestijli ──
        ["sancaktepe"]  = "Sancaktepe, Veysel Karani ve Fatih mahallelerindeki toplu konut projeleriyle hızla gelişen, Anadolu yakasının yeni cazibe merkezi konumundaki ilçedir. Sancaktepe Merkez'deki planlı yapı stoku asansörlü binaları ağırlıklı olarak barındırmakta; yükleme operasyonları verimli biçimde planlanabilmektedir. Ümraniye ve Kartal güzergâhlarından TEM'e bağlantı sağlanmakta olup sabah trafiği sakinleştiğinde çıkış tercih edilmektedir. Kaynarca ve Eyüp Sultan mahallelerindeki sitelerde geniş araç erişim yolları büyük araçlar için de uygundur.",
        ["sultanbeyli"] = "Sultanbeyli, İstanbul Anadolu yakasının en yoğun konut nüfusuna sahip ilçelerinden biri olup Mehmet Akif, Battalpasa ve Hasanpaşa mahallelerinde binlerce konut bloğu bulunmaktadır. İlçe genelinde sokak dokusu yoğun ve zaman zaman dar olduğundan 3,5 ton kamyonet ağırlıklı olarak tercih edilmekte; büyük daireler için ise asansör planlamasıyla kamyon erişimi sağlanmaktadır. E-5 ve D-100'a Kartal aksından ulaşılmakta; TEM Kurtköy bağlantısı ile Ankara yoluna giriş yapılmaktadır. Sabah trafiğine yakalanmamak için yüklemenin 07:00'den önce tamamlanması önerilmektedir.",
        ["tuzla"]       = "Tuzla, İçmeler sahil şeridinden Mimar Sinan'ın organize sanayi bölgelerine uzanan, sanayi ve konutun iç içe geçtiği İstanbul'un güneydoğu ilçesidir. OSB'ye alışkın lojistik altyapı büyük tonajlı araçların hareketini kolaylaştırmakta; Aydınlı ve Postane mahallelerindeki konut bölgelerine ise 3,5 ton kamyonetle erişilmektedir. D-100 ve E-5'e doğrudan bağlantısı bulunan ilçede TEM girişine Kurtköy üzerinden 20 dakikada ulaşılmaktadır. Özellikle kurumsal ofis ve sanayi tesis taşımalarında ilçenin büyük araç deneyimi belirleyici avantaj sağlamaktadır.",
        ["sile"]        = "Şile, Karadeniz kıyısında doğal güzellikleri ve yazlık konutlarıyla tanınan, İstanbul'un en uzak ilçelerinden biridir. İlçe merkezine ulaşım için E-80'den Kurtköy–Şile yolu kullanılmakta; bu güzergâh hem kalıcı konut hem de yaz döneminde yoğunlaşan yazlık taşımalarına hizmet etmektedir. Büyük araç erişimi ilçe merkezi ve ana sokaklar için uygundur; köy bölgelerinde ve bazı kıyı mahallelerinde kamyonet tercih edilmektedir. Ankara güzergâhı için Ümraniye aksından TEM'e ulaşılmakta olup uzun güzergâh nedeniyle sabah erken çıkış zorunludur.",
        ["adalar"]      = "Adalar, motorlu taşıtların yasak olduğu Büyükada, Heybeliada, Burgazada ve Kınalıada'dan oluşan İstanbul'un özgün ilçesidir. Taşımacılık araçların adaya girişinin yasak olması nedeniyle özel koordinasyon gerekmektedir: eşyalar karşı yakada kıyıya bırakılmakta, adanın içinde fayton veya belediye aracıyla son noktaya ulaştırılmaktadır. Ankara nakliyatları için eşyalar Kadıköy veya Pendik iskelesi üzerinden kara bağlantısına alınmakta; bu transfer süreci rezervasyon aşamasında planlı biçimde yönetilmektedir. Taşıma süresi ve maliyeti adadan kıta bağlantısına olan mesafeye göre değişmektedir.",
        ["sisli"]       = "Şişli, Nişantaşı'nın lüks konut dokusu, Mecidiyeköy'ün iş kuleleri ve Bomonti'nin dönüşen sanayi alanlarıyla İstanbul'un prestijli Avrupa yakası ilçelerinden biridir. Mecidiyeköy ve Levent aksında yoğun araç trafiği nedeniyle büyük kamyonlar için gece veya sabah erken yükleme saati tercih edilmektedir. TEM ve E-5'e Zincirlikuyu–TEM bağlantısından ya da Maslak aksından ulaşılmaktadır. Nişantaşı'nın tarihi apartmanlarında asansör kapasitesi sınırlı olabilmekte; kat başına taşıma süresi ve ekip sayısı önceden planlanmaktadır.",
        ["besiktas"]    = "Beşiktaş, Boğaz kıyısındaki Ortaköy ve Bebek'in köklü mahalle dokusu ile Levent ve Etiler'in modern rezidans ve iş merkezlerini bir arada barındıran İstanbul'un en prestijli ilçesidir. Bebek, Arnavutköy ve Ortaköy'ün Boğaz yalı sokakları büyük araç erişimi için dar olabilmektedir; bu bölgelerde 3,5 ton kamyonet veya kombinasyon taşıma uygulanmaktadır. Levent ve Balmumcu'daki modern yapılarda geniş bina girişleri büyük mobilyaların hasarsız taşınmasına imkân tanımaktadır. TEM'e Maslak aksından ulaşılmakta olup sabah mesai öncesi çıkış Boğaz trafiğini aşmayı sağlamaktadır.",
        ["bakirkoy"]    = "Bakırköy, Ataköy'ün prestijli sahil sitelerinden Florya'nın köklü konut dokusuna uzanan, gelişmiş altyapısıyla Avrupa yakasının merkezi ilçesidir. Ataköy ve Florya'daki büyük sitelerde geniş araç erişim yolları ve asansörlü yapılar yükleme operasyonlarını kolaylaştırmaktadır. E-5 üzerinde konumlanan ilçe, Ankara güzergâhına D-100 ve TEM bağlantısından hızla erişim sağlamaktadır. Zuhuratbaba ve Cevizlik mahallelerindeki daha eski apartman yapılarında merdiven taşıması için ek süre hesaba katılmaktadır.",
        ["beylikduzu"]  = "Beylikdüzü, Büyükşehir ve Adnan Kahveci mahallelerindeki büyük konut siteleri ile alışveriş merkezi yoğunluğuyla İstanbul'un batısındaki modern ilçesidir. Geniş anayollar ve planlı kentsel yapı, hem kamyonet hem kamyon operasyonları için ideal çalışma ortamı sunmaktadır. TEM'e Esenyurt aksından yaklaşık 15 dakikada ulaşılmakta; sabah trafiği Metrobüs güzergâhının ilçeyi kesen aksında yoğunlaşmaktadır. Özellikle büyük sitelerdeki 2+1 ve 3+1 dairelerde yükleme asansörü koordinasyonuyla verimli taşıma süresi sağlanmaktadır.",

        // ── GRUP 3: Batı / Kuzey İstanbul ──
        ["esenyurt"]       = "Esenyurt, İstanbul'un en hızlı büyüyen ve en kalabalık ilçelerinden biri olup Talatpaşa, Saadetdere ve Pınar mahallelerindeki yoğun konut yapısıyla öne çıkmaktadır. Sabah ve akşam saatlerinde araç trafiği yoğunlaşmakta; taşıma operasyonları için 07:00 öncesi yükleme başlatılması önerilmektedir. TEM'e Avcılar veya Başakşehir aksından ulaşılmaktadır. Yeni konut bloklarının çoğunda asansörlü yapı standardı bulunmakta; eski stokta ise kat başına taşıma süresi önceden hesaplanmaktadır.",
        ["basaksehir"]     = "Başakşehir, Bahçeşehir, Kayaşehir ve Altınşehir'deki planlı yapısıyla İstanbul'un modern ve düzenli Avrupa yakası ilçelerinden biridir. Geniş bina girişleri, asansörlü yapılar ve araç erişimine uygun yollar yükleme operasyonlarını kolaylaştırmaktadır. TEM'e doğrudan bağlantısı bulunan ilçe, İstanbul'dan Ankara güzergâhına en kısa çıkışlardan birini sunmaktadır. Büyük kamyon ve şehirlerarası araçlar için ideal güzergâh konumundadır; sabah yüklemesiyle öğleden önce TEM'e girilmektedir.",
        ["arnavutkoy"]     = "Arnavutköy, İstanbul Havalimanı'na sıfır mesafedeki konumuyla ulaşım açısından stratejik bir ilçedir. Bolluca ve Haraçcı mahallelerindeki yeni konut projelerinde asansörlü yapılar yaygındır. TEM'e Arnavutköy çevreyolu üzerinden yaklaşık 15–20 dakikada ulaşılmaktadır. Özellikle İstanbul Havalimanı personeli ve yakın çevresindeki konut taşımalarında yoğun talep yaşanmaktadır.",
        ["hadimkoy"]       = "Hadımköy, TEM otoyoluna ve İstanbul Havalimanı'na fiilen en yakın sanayi ve lojistik merkezidir. OSB'nin büyük araç altyapısına alışkın ortamı, hem ticari hem konut taşımacılığını kolaylaştırmaktadır. TEM girişine 5 dakikadan kısa sürede ulaşılabilmesi, Ankara taşımalarında trafik riskini sıfıra indirmektedir. Hadımköy Merkez mahallelerindeki konut bölgelerine kamyonet erişimi sorunsuz sağlanmakta; yeni sitelerde ise geniş araç yolları kamyon operasyonlarına elverişlidir.",
        ["ikitelli"]       = "İkitelli, İstanbul'un en büyük organize sanayi bölgelerinden birini barındıran ve çevresinde hızla konutlaşan batı ilçesidir. OSB'nin büyük araç altyapısı kurumsal taşımacılık için ideal ortam sunmakta; Kazım Karabekir ve Ziya Gökalp mahallelerindeki konut bölgelerine ise kamyonet erişimi sorunsuz sağlanmaktadır. TEM'e Başakşehir ve Küçükçekmece aksından bağlantı kurulmakta; sabah saatlerinde OSB giriş çıkışı yoğun olduğundan yükleme saatinin buna göre planlanması önerilmektedir. Kanarya ve Mehmet Akif mahallelerindeki yeni yapılarda asansörlü bina oranı artmaktadır.",
        ["avcilar"]        = "Avcılar, Ambarlı'nın limanı ve sanayi bölgesiyle birlikte Marmara kıyısındaki üniversite kampüsü çevresinde gelişen, karma yapılı bir Avrupa yakası ilçesidir. Ambarlı ve Firuzköy'deki sanayi bölgelerinde büyük araç trafiğine alışkın altyapı bulunmakta; konut mahallelerinde ise 3,5 ton kamyonet ağırlıklı olarak kullanılmaktadır. E-5'e hızla ulaşılabilmekte, TEM bağlantısı Küçükçekmece veya Esenyurt aksından sağlanmaktadır. Üniversite kampüsü nedeniyle öğrenci taşımalarında parsiyel araç talebi yoğundur.",
        ["buyukcekemece"]  = "Büyükçekmece, Mimarsinan ve Kumburgaz'ın yazlık sahil siteleriyle Pınarca ve Güzelce'nin kalıcı konut alanlarını barındıran İstanbul'un batısındaki sakin ilçesidir. Sahil kesimindeki sitelerde geniş araç yolları ve planlı parsel yapısı büyük taşıma araçlarının hareketini kolaylaştırmaktadır. E-5 ve TEM'e Avcılar veya Esenyurt aksından bağlanılmakta; Ankara güzergâhına sakin sabah saatlerinde çıkış önerilmektedir. Yaz sezonunda yazlık konut taşımalarında talep artmakta; erken rezervasyon önerilmektedir.",
        ["silivri"]        = "Silivri, Marmara kıyısındaki geniş yazlık konut siteleri ve bağ evi bölgeleriyle İstanbul'un en batı ilçesi konumundadır. Selimpaşa ve Gümüşyaka'daki siteler büyük araç erişimine uygun geniş yollara sahipken bağ bölgelerinde kamyonet tercih edilmektedir. E-5 ve TEM'e Büyükçekmece güzergâhından ulaşılmakta; Ankara mesafesi İstanbul merkezine kıyasla benzer düzeyde kalmaktadır. Özellikle kış–yaz arası geçiş dönemlerinde yazlık–şehir taşıma talebi yoğunlaşmaktadır.",
        ["catalca"]        = "Çatalca, İstanbul'un yüzölçümü en büyük ilçesi olup orman alanları, kırsal köyler ve küçük yerleşim merkezlerinden oluşmaktadır. İlçe merkezine ve büyük mahallelere ana karayolu üzerinden kamyon erişimi mümkün olsa da köy yollarında kamyonet ile hizmet verilmektedir. E-5 ve TEM'e Silivri veya Büyükçekmece üzerinden bağlanılmakta; Ankara güzergâhına girerken bu şeritler kullanılmaktadır. Taşımadan önce adres bazlı araç erişim değerlendirmesi yapılması önerilmektedir.",

        // ── GRUP 4: Avrupa Yakası Orta ──
        ["kucukcekemece"] = "Küçükçekmece, Atakent ve Halkalı'nın modern konut siteleri ile İnönü ve Cennet mahallelerinin köklü yapı stoğuyla Avrupa yakasının göl kıyısındaki dinamik ilçesidir. Halkalı'nın tren bağlantısı ve E-5 üzerindeki konumu, nakliyat araçlarının ilçeyi hızla terk etmesine imkân tanımaktadır. TEM'e Esenyurt veya Bakırköy aksından ulaşılmaktadır; sabah yüklemesiyle Ankara güzergâhına sorunsuz girilmektedir. Atakent'teki büyük sitelerde geniş bina girişleri kamyon erişimine elverişliyken eski yapılarda kamyonet ile hizmet verilmektedir.",
        ["gungoren"]      = "Güngören, Güngören Merkez, Tozkoparan ve Merter mahallelerinde tekstil atölyeleri, ticarethaneler ve yoğun konut dokusunu bir arada barındıran İstanbul'un kalabalık ilçelerinden biridir. İlçe genelinde dar iç sokaklar yaygın olduğundan 3,5 ton kamyonet büyük dairelerde bile tercih sebebi olmaktadır; geniş mobil ekip koordinasyonu ile yükleme hızlandırılmaktadır. E-5 ve TEM bağlantısı Bakırköy veya Bağcılar aksından sağlanmaktadır. Sabah yükleme trafikten önce tamamlandığında Ankara güzergâhına saat 09:00'da girilmektedir.",
        ["bahcelievler"]  = "Bahçelievler, Kocasinan, Şirinevler ve Zafer mahallelerindeki yoğun konut bloklarıyla Avrupa yakasının merkezi ilçelerinden biridir. E-5 üzerindeki konumu Ankara güzergâhına doğrudan bağlantı sağlamakta; Şirinevler bağlantısıyla TEM'e de hızla ulaşılmaktadır. Yüksek yapı yoğunluğu nedeniyle sabah 07:00 öncesi yükleme başlatılması araç çıkışını kolaylaştırmaktadır. İlçedeki çok katlı konut yapılarının büyük bölümünde asansörlü bina standardı bulunmaktadır.",
        ["bagcilar"]      = "Bağcılar, İstanbul'un en kalabalık ilçelerinden biri olup Bağcılar Merkez, Göztepe ve Kirazlı mahallelerinde binlerce konut bloğu bulunmaktadır. İlçe genelinde trafik sabah ve akşam saatlerinde çok yoğunlaşmakta; taşıma araçları için 07:00 öncesi yükleme önerilmektedir. TEM'e Esenyurt veya Bağcılar çevreyolundan bağlanılmaktadır. Yeni yapılarda asansörlü bina standardı yaygınlaşmış olsa da eski stoktaki kat taşımalarında ek süre ve ekip planlanmaktadır.",
        ["esenler"]       = "Esenler, İstanbul Büyük Otogar'ına sıfır mesafesiyle şehirlerarası ulaşımın merkezi konumunda bir ilçedir. Otogara alışkın büyük araç trafiği, nakliyat araçlarının ilçede rahatça hareket etmesini sağlamaktadır. TEM'e Bağcılar veya Bayrampaşa aksından bağlanılmakta olup sabah saatlerinde erken çıkış önerilmektedir. Kemer ve Çiftlik mahallelerindeki yeni yapılarda asansörlü bina standardı artmaktadır.",
        ["bayrampasa"]    = "Bayrampaşa, E-5 ve TEM akslarına yakın konumuyla nakliyat araçlarının Ankara güzergâhına hızla ulaşabildiği bir Avrupa yakası ilçesidir. Bayrampaşa Merkez ve Kocatepe mahallelerindeki yüksek katlı konutlarda asansör koordinasyonu standarttır. İlçe içi bazı dar sokaklarda büyük kamyon erişimi kısıtlı olabildiğinden adres bazlı araç seçimi yapılmaktadır. TEM'e Zeytinburnu veya Esenler güzergâhından kısa sürede ulaşılmaktadır.",
        ["gaziosmanpasa"] = "Gaziosmanpaşa, Barbaros, Karadeniz ve Yenidoğan mahallelerindeki köklü yerleşim dokusunu barındıran kuzey Avrupa yakası ilçesidir. İlçe içi sokak dokusu yoğun olduğundan 3,5 ton kamyonet çoğu mahallede standart çözüm olmaktadır; geniş arterlere yakın adreslerde kamyon erişimi de mümkündür. TEM'e Sultangazi veya Eyüpsultan güzergâhından ulaşılmaktadır. Özellikle Yenidoğan'daki kentsel dönüşüm projeleriyle birlikte asansörlü yeni yapılarda taşıma talebi artmaktadır.",

        // ── GRUP 5: Tarihi / Kuzey Avrupa Yakası ──
        ["sultangazi"]    = "Sultangazi, Cebeci, Uğur Mumcu ve Sultançiftliği mahallelerindeki planlı konut yapısıyla kuzey İstanbul'un hızla gelişen ilçesidir. Yeni konut projelerinde asansörlü yapı standardı yaygındır; eski stokta kat başına taşıma süresi önceden hesaplanmaktadır. TEM'e Arnavutköy veya Eyüpsultan üzerinden ulaşılmakta; sabah yüklemesinde Ankara güzergâhına sorunsuz çıkılmaktadır. Habibler ve Malkoçoğlu mahallelerindeki bazı dar sokaklarda kamyonet tercih edilmekte, geniş arterlere yakın adreslerde ise kamyon erişimi sağlanmaktadır.",
        ["kagithane"]     = "Kağıthane, Çağlayan, Gültepe ve Seyrantepe mahallelerindeki kentsel dönüşüm projeleriyle son yıllarda yenilenen ve değer kazanan merkezi bir İstanbul ilçesidir. İlçe içinde bazı dar ve eğimli sokaklar bulunmakla birlikte ana arterler ve Seyrantepe aksı büyük araç erişimine elverişlidir. TEM'e Maslak aksından ya da Gaziosmanpaşa üzerinden ulaşılmaktadır. Yeni yapılarda asansörlü bina standardı yaygınlaşmış olup eski stoktaki kat taşımalarında ek süre hesaba katılmaktadır.",
        ["beyoglu"]       = "Beyoğlu, Taksim, Cihangir, Galata ve Karaköy gibi İstanbul'un en tarihi ve kültürel mahallelerini barındıran, eğimli arazisiyle kendine özgü bir lojistik yapısına sahip ilçedir. Dar ve eğimli sokaklar, kaldırım taşlı yollar ve bazı bölgelerdeki araç kısıtlamaları nedeniyle büyük kamyon erişimi sınırlıdır; 3,5 ton kamyonet standart çözüm olmaktadır. Nişantaşı ve Harbiye aksındaki geniş caddelerde daha büyük araç geçişi mümkündür. TEM'e Maslak veya Şişli aksından ulaşılmakta; sabah erken çıkış turist trafiğini atlatmayı sağlamaktadır.",
        ["fatih"]         = "Fatih, Aksaray, Samatya, Yedikule ve Balat gibi tarihi yarımadanın en yoğun ve köklü mahallelerini barındıran İstanbul'un en eski ilçesidir. Tarihi yarımadadaki dar sokak dokusu ve trafik düzenlemeleri nedeniyle büyük araç geçişleri belirli gün ve saatlere tabidir; 3,5 ton kamyonet büyük çoğunlukta standart çözümdür. Kocamustafapaşa ve Yenibosna akslarına yakın adreslerde ise uygun saatlerle kamyon erişimi sağlanabilmektedir. TEM bağlantısı Zeytinburnu veya Bayrampaşa güzergâhından kurulmaktadır.",
        ["eyupsultan"]    = "Eyüpsultan, Alibeyköy'ün kalabalık konut bölgeleri ile Göktürk'ün lüks müstakil villa alanlarını aynı anda barındıran tarihi bir İstanbul ilçesidir. Alibeyköy ve Nişanca mahallelerinde yoğun konut dokusu nedeniyle dar sokaklarda kamyonet ağırlıklı hizmet verilmekte; Göktürk'te ise geniş parsel ve yollar büyük araç erişimine elverişlidir. TEM'e Arnavutköy veya Sultangazi aksından ulaşılmaktadır. Özellikle Göktürk villa bölgesinden değerli ve büyük mobilya taşımalarında özel ambalaj uygulanmaktadır.",
        ["sariyer"]       = "Sarıyer, Yeniköy, Tarabya, Büyükdere ve Zekeriyaköy gibi Boğaz kıyısı ve kuzey İstanbul ormanlarına dayanan huzurlu mahallelerini barındıran ilçedir. Boğaz kıyısındaki yalı ve yüksek değerli konutlarda dar ve köklü sokak dokusu büyük araç erişimini güçleştirmektedir; 3,5 ton kamyonet standart araç olmaktadır. İstinye ve Büyükdere caddesindeki modern yapılarda geniş bina girişleri daha büyük araçlara imkân tanımaktadır. TEM'e Maslak aksından ulaşılmakta; sabah erken çıkış Boğaz güzergâhındaki yoğunluğu atlatmayı sağlamaktadır.",
        ["zeytinburnu"]   = "Zeytinburnu, Kazlıçeşme'nin deri ve tekstil sanayi geçmişinden Merkezefendi'nin modern konut projelerine uzanan köklü bir sanayi ve konut ilçesidir. E-5 üzerinde konumlanan ilçede Ankara güzergâhına doğrudan erişim sağlanmakta; geniş sanayi arterleri büyük araç geçişine elverişlidir. Seyitnizam ve Veliefendi mahallelerindeki konut bloklarında asansör koordinasyonu standarttır. Nuripaşa ve Kazlıçeşme'nin kısmen dar sanayi sokaklarında ise kamyonet tercih edilmektedir.",
    };

    private static readonly Dictionary<(string Ilce, ServisTipi Servis), string> ServisDetaylar = new()
    {
        // ── KADIKOY ──
        [("kadikoy", ServisTipi.Kamyonet)]      = "Moda ve Kalamış'ın dar kaldırım sokaklarında bina önü araç durağı müsaitliği rezervasyon aşamasında kontrol edilmekte, gerektiğinde geçici duraklama düzenlemesiyle yükleme başlatılmaktadır. Caferağa ve Mühürdar gibi eski doku mahallelerinde asansörsüz binalarda kat başına taşıma süresi ekip sayısına göre önceden hesaplanmakta; 3,5 ton kamyonetimiz dar manevra alanlarına kolaylıkla uyum sağlamaktadır.\n\nFikirtepe'deki kentsel dönüşüm projelerinin yeni yapılarında ise geniş bina girişleri ve yük asansörleri yüklemeyi önemli ölçüde hızlandırmaktadır. Kadıköy içi trafik sabah 07:00'den itibaren yoğunlaşmakta; bu nedenle yükleme 06:30'da başlatılarak araç bölgeyi terk etmeden önce Ümraniye aksına yönlenmektedir. Böylece köprü yoğunluğuna yakalanmadan Ankara güzergâhına rahatça girilmektedir.",
        [("kadikoy", ServisTipi.Sehirlerarasi)] = "Kadıköy merkezi konumuyla sabah 06:30–07:00 arasında yüklemeye başlanmakta; Ümraniye aksından TEM'e 15–20 dakikada bağlanılarak köprü trafiği yoğunlaşmadan İstanbul geride bırakılmaktadır. Yükleme planlaması mobilya söküm süresi, kat adedi ve asansör kapasitesine göre kişiselleştirilmekte; taşınan her eşya envanter listesiyle kayıt altına alınmaktadır.\n\nTEM'e Ümraniye kavşağından giriş yapıldıktan sonra güzergâh büyük ölçüde açık akmakta ve öğle saatlerine kadar Ankara varışı tamamlanmaktadır. Kadıköy'den Ankara'nın Çankaya, Kızılay ve Eryaman gibi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir. Tüm şehirlerarası taşımalarda nakliye sigortası kapsam bilgisi müşteriye önceden yazılı olarak sunulmaktadır.",
        [("kadikoy", ServisTipi.EvdenEve)]      = "Kadıköy ev nakliyelerinde Caferağa ve Fenerbahçe'nin asansörsüz tarihi apartmanlarında kat başına çalışan uzman ekip, büyük mobilyaların sökümünden ambalajına kadar tüm süreci yönetmektedir; her parça balonlu naylon ve battaniye ile korunarak yüklenmektedir. Yükleme öncesi fotoğraflı değerlendirmeyle kat sayısı, asansör boyutu ve büyük mobilya ölçüleri netleştirilmekte; operasyon günü sürprizle karşılaşılmamaktadır.\n\nAnkara'daki yeni konuta varışta sökülen mobilyalar ekibimiz tarafından monte edilmekte, kutu ambalajları açılmakta ve eşyalar istenilen odaya yerleştirilmektedir. Bostancı ve Erenköy'deki geniş dairelerde büyük mobilyaların bina içinde taşınması için gerektiğinde merdiven araç koordinasyonu da önceden planlanmaktadır. Tüm süreç, müşterinin Ankara'daki yeni evinde rahatça yerleşmesiyle tamamlanmaktadır.",
        [("kadikoy", ServisTipi.Ofis)]          = "Kadıköy'deki finans, hukuk ve kreatif ofislerin Ankara'ya taşınmasında IT ekipmanı özel anti-statik ambalajla paketlenmekte; sunucu, ekran ve ağ cihazları ayrı ayrı etiketlenerek Ankara'da hızla kuruluma hazır hâle getirilmektedir. Gizlilik gerektiren arşiv dosyaları mühürlü kolilere konulmakta ve teslimat anında imza karşılığı teslim edilmektedir.\n\nHafta içi ofis faaliyetini kesintisiz sürdürebilmek için taşıma çoğunlukla cuma gecesi veya hafta sonu başlatılmaktadır. Ankara'daki kurulum ekibimiz masaları, raf sistemlerini ve kablo düzenini orijinal ofis planına uygun biçimde monte etmektedir. Kurumsal fatura, sigorta belgesi ve detaylı yük envanteri taşıma paketinin standart bileşenleri arasındadır.",
        [("kadikoy", ServisTipi.Fuar)]          = "Kadıköy'deki tasarım, reklam ve medya ajanslarının Ankara CNR veya Tüyap fuar alanlarına taşınan stand profilleri, pano sistemleri ve display materyalleri vibrasyona karşı dayanıklı ambalajlarla hazırlanmaktadır. Grafik baskılar ve backlitler koruyucu rulolar içinde; monitör ve ekranlar ise özel köpük kesim ambalajlarla iletilmektedir.\n\nFuar açılışından en az 2 gün önce teslimat garanti edilmektedir; gecikmeler riski gözetilerek kalkış zamanı müşteriyle birlikte planlanmaktadır. Ankara fuar alanlarındaki operasyon ekibi isteğe bağlı olarak stand kurulum koordinasyonunu da üstlenebilmektedir. Fuar sonrası geri taşıma rezervasyonu ilk teslimatla birlikte yapılarak sezon yoğunluğunda yer güvencesi sağlanmaktadır.",
        [("kadikoy", ServisTipi.Kamyon)]        = "Bostancı ve Erenköy'deki 3+1–4+1 büyük dairelerden Ankara'ya taşımalarda 12 ton kapalı kasalı kamyon tek seferlik nakliye için idealdir; büyük mobilyaların tamamı tek araçta konsolide edilerek gereksiz ikinci sefer maliyetinden kaçınılmaktadır. Kamyon yüklemesi için Bostancı ve İskele caddesi çevresi erişime uygun olmakta, gerektiğinde yetkili birimle koordineli geçici duraklama düzenlenmektedir.\n\nTüm eşyalar hareket öncesinde sigorta kapsamına alınmakta; kırılgan ve değerli parçalar için ek koruma ambalajı seçeneği sunulmaktadır. Ankara'ya varışta kamyon adrese yaklaşmakta, ekip indirme ve odaya yerleştirme işlemini tamamlamaktadır. Kadıköy'den Ankara'ya kamyon taşıması için sabah 06:00–07:00 arası kalkış tercih edilmektedir.",
        [("kadikoy", ServisTipi.Parsiyel)]      = "Kadıköy'den Ankara'ya yalnızca birkaç parça mobilya, beyaz eşya veya kargo kutusu göndermek isteyen müşteriler için paylaşımlı parsiyel araç hizmeti, tam araç kiralama maliyetinin çok altında ekonomik çözüm sunmaktadır. Eşyalar güvenli biçimde paketlendikten sonra diğer parsiyel yüklerle birleştirilerek Ankara'ya yönelik düzenli sefer aracına yüklenmektedir.\n\nParsiyel gönderi ağırlık ve hacme göre fiyatlandırılmakta; teklif rezervasyon sırasında sabitlenmektedir. Kadıköy toplama noktasından Ankara adres teslimatına kadar geçen süre genellikle 1–2 iş günüdür ve teslimat günü müşteriye önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği parsiyel hizmette de geçerlidir.",
        [("kadikoy", ServisTipi.Ambar)]         = "Kadıköy'deki evi boşaltırken Ankara'daki yeni konuta taşınma tarihi henüz netleşmemiş ya da anahtar teslimi bekleyen müşteriler için eşyalar güvenli depomuzda kilitli alanda muhafaza edilmektedir. Depolama süresi esnek olup haftalık veya aylık dönemler halinde planlanabilmekte; kısa süreli köprü depolamadan uzun vadeli saklamaya kadar tüm senaryolar karşılanmaktadır.\n\nDepodan çıkışta eşyalar Ankara adresine teslim edilmekte ve ek nakliye planlaması gerektiğinde öncelikli rezervasyon hakkı tanınmaktadır. Depo alanı kamera sistemi, nem kontrolü ve yangın önlemiyle donatılmış olup hassas eşyalar için bireysel kilitli alan tahsis edilebilmektedir. Depolama süresi ve ücreti rezervasyon aşamasında yazılı olarak teyit edilmektedir.",

        // ── ÜSKÜDAR ──
        [("uskudar", ServisTipi.Kamyonet)]      = "Çengelköy ve Kandilli'nin Boğaz kıyısındaki yalı sokaklarında büyük kamyon geçişi hem fiziksel kısıtlar hem de tarihi doku koruması açısından mümkün olmamakta; 3,5 ton kamyonetimiz standart çözüm olarak uygulanmaktadır. Kuzguncuk ve Beylerbeyi'nin köklü mahallelerinde dar kapı aralıkları için mobilya söküm ekibi önceden organize edilmektedir.\n\nAltunizade ve Acıbadem'deki modern rezidans yapılarında ise yük asansörü ve geniş bina girişleri yüklemeyi hızlandırmaktadır. Üsküdar'dan TEM'e Selimiye aksıyla Ümraniye üzerinden bağlantı sağlanmakta; sabah 06:30'da kalkışla köprü trafiği aşılarak Ankara güzergâhına girilmektedir.",
        [("uskudar", ServisTipi.Sehirlerarasi)] = "Üsküdar Anadolu yakasının tarihi merkezi olarak şehirlerarası araçlar Selimiye aksıyla Ümraniye üzerinden TEM'e bağlanmakta; sabah erken yüklemeyle gün içinde Ankara varışı tamamlanmaktadır. Boğaz kıyısındaki bazı mahallelerde dar sokak yapısı nedeniyle araç kademeli ilerlemekte; yükleme süresi keşifte hesaplanmaktadır.\n\nTüm eşyalar envanter listesiyle kayıt altına alınmakta ve nakliye sigortasıyla güvence altına alınmaktadır. Üsküdar'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("uskudar", ServisTipi.EvdenEve)]      = "Altunizade ve Acıbadem'deki modern yüksek katlı yapılarda asansör ön rezervasyonu ve komşu koordinasyonuyla büyük mobilyalar hasarsız indirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunarak yüklenmekte; taşıma öncesinde kapsamlı envanter dökümü yapılmaktadır.\n\nÇengelköy ve Kuzguncuk'taki tarihi yapılarda ise asansör olmadığından kat başına ekip planlaması yapılmakta; büyük mobilyalar sökülerek merdivenden taşınmaktadır. Ankara'daki yeni konuta teslimatta ekip mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("uskudar", ServisTipi.Ofis)]          = "Altunizade iş merkezlerinden ve Üsküdar'daki profesyonel ofislerden Ankara'ya kurumsal taşımalarda IT altyapısı güvenlik protokolüne göre demonte edilmekte; Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir. Taşıma hafta sonu ya da gece tercih edilmekte; çalışan kesintisizliği öncelikli hedef olmaktadır.\n\nKurumsal fatura, sigorta belgesi, envanter listesi ve teslim tutanağı her ofis nakliyesinde standart olarak sunulmaktadır. IT ekipmanı anti-statik ambalajla, sunucular ise özel koruyucu kasayla iletilmektedir.",
        [("uskudar", ServisTipi.Fuar)]          = "Üsküdar'daki firma ve ajansların Ankara fuar alanlarına gönderilen stand materyalleri, display sistemleri ve promosyon gereçleri özel ambalajla güvence altına alınmaktadır. Nakliye planlaması fuar takvimi ve kurulum günü baz alınarak yapılmakta; zamanında teslimat garanti edilmektedir.\n\nFuar açılışından 2 gün önce Ankara alanında teslim taahhüt edilmektedir. Fuar sonrası geri taşıma için aynı araç standardı uygulanmakta; hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("uskudar", ServisTipi.Kamyon)]        = "Beylerbeyi ve Çengelköy'deki yalı ve köşk tipi büyük konutlardan Ankara'ya değerli mobilyalar ve büyük ev eşyaları taşımalarında 12–18 ton kapalı kasalı kamyon kullanılmaktadır. Antika mobilya ve kırılgan parçalar için özel köpük kesim ambalaj uygulanmakta; yola çıkmadan önce sigorta aktive edilmektedir.\n\nKamyon yüklemesi Boğaz kıyısındaki dar sokaklarda kamyonet aktarmasıyla yapılabilmekte ya da geniş artere yakın adreslerde doğrudan yükleme mümkün olmaktadır. Ankara'ya varışta ekip eşyaları odaya taşımakta ve büyük mobilyaları monte etmektedir.",
        [("uskudar", ServisTipi.Parsiyel)]      = "Üsküdar'dan Ankara'ya birkaç parça mobilya, beyaz eşya veya kargo göndermek isteyen müşteriler için parsiyel araç hizmeti ekonomik ve zamanında teslimat sunar. Gönderiler Ankara yönlü konsolide sefere dahil edilmekte; ağırlık ve hacme göre fiyatlandırılmaktadır.\n\nToplama adresinden Ankara teslim noktasına kadar 1–2 iş günü süre öngörülmekte; teslimat günü önceden bildirilmektedir. Kırılgan parçalar için ekstra ambalaj seçeneği geçerlidir.",
        [("uskudar", ServisTipi.Ambar)]         = "Üsküdar'daki evi boşaltırken Ankara'daki yeni konuta anahtar teslimi bekleyen veya taşınma tarihi esnek olan müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nDepodan çıkışta eşyalar Ankara adresine teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── ÜMRANİYE ──
        [("umraniye", ServisTipi.Kamyonet)]      = "Armağanevler ve Yunus Emre mahallelerindeki çok katlı konut bloklarında 3,5 ton kamyonetimiz asansör koordinasyonuyla verimli yükleme gerçekleştirmektedir; site girişleri ve yükleme alanları önceden yönetimle koordine edilmektedir. İnkılap ve Siteler'deki geniş konut parsellerinde büyük araçlar da sorunsuz çalışmaktadır.\n\nÜmraniye'nin TEM girişine 5–10 dakika mesafesi, şehirlerarası araçların İstanbul trafiğine girmeden doğrudan Ankara yoluna çıkmasını sağlamaktadır. Sabah 06:30 kalkışla günün erken saatinde Ankara varışı rahatça tamamlanmaktadır.",
        [("umraniye", ServisTipi.Sehirlerarasi)] = "Ümraniye'nin Anadolu yakasında TEM bağlantısına en yakın konumdaki ilçelerden biri olması, şehirlerarası taşımalarda rakipsiz güzergâh avantajı yaratmaktadır. Yükleme tamamlanır tamamlanmaz araç TEM'e bağlanmakta; uzun mesafe güzergâhında İstanbul trafiğinden kaynaklanan zaman kaybı sıfırlanmaktadır.\n\nTüm eşyalar yükleme öncesinde sigorta kapsamına alınmakta ve ayrıntılı envanter listesiyle belgelenmektedir. Ümraniye'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("umraniye", ServisTipi.EvdenEve)]      = "İnkılap ve Siteler mahallelerindeki geniş girişli yeni yapılarda ekibimiz asansör planlaması ve komşu koordinasyonuyla hızlı ve verimli yükleme gerçekleştirmektedir. Büyük mobilyalar söküm-montaj ekibiyle parçalara ayrılmakta, her parça koruyucu ambalajla Ankara yoluna hazırlanmaktadır.\n\nÜmraniye'deki kentsel dönüşüm alanlarında hem eski hem yeni bina tiplerine yönelik deneyimli ekibimiz her türlü yapıyı etkin biçimde yönetmektedir. Ankara'daki yeni adrese varışta tüm mobilyalar monte edilmekte; müşteri eşdeğer yerleşim standardında aynı gün evine kavuşmaktadır.",
        [("umraniye", ServisTipi.Ofis)]          = "Ümraniye'deki teknoloji firmaları, yazılım şirketleri ve finans kuruluşlarının Ankara'ya kurumsal taşımalarında IT altyapısı güvenli biçimde paketlenmekte; sunucu rafları, ağ cihazları ve UPS üniteler özel kasalarda iletilmektedir. Kablolama fotoğraflanmakta; Ankara'da mevcut plan yeniden oluşturulmaktadır.\n\nTaşıma hafta sonu tercih edilmekte; pazartesi sabahı personel çalışmaya hazır ofiste başlamaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi standart olarak sunulmaktadır.",
        [("umraniye", ServisTipi.Fuar)]          = "Ümraniye'deki teknik donanım, elektronik ve sanayi firmalarının Ankara fuar alanlarına taşınan ekipmanları vibrasyon emici ambalajlarla ve ESD standartlarına uygun şekilde hazırlanmaktadır. Hassas teknik cihazlar özel şok emici kasalarda iletilmektedir.\n\nFuar açılışından 2 gün önce teslimat taahhüt edilmektedir. Fuar sonrası dönüş taşıması rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır.",
        [("umraniye", ServisTipi.Kamyon)]        = "Ümraniye'deki 3+1 ve üzeri büyük dairelerden Ankara'ya 12–18 ton kamyon ile tek seferlik taşıma, TEM'e en kısa mesafedeki güzergâhtan geçmektedir. Yük miktarına göre araç tipi seçilmekte; birden fazla seferden kaçınmak için yük planlaması keşif aşamasında yapılmaktadır.\n\nTüm eşyalar hareket öncesinde envanter fotoğrafıyla belgelenerek sigorta altına alınmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("umraniye", ServisTipi.Parsiyel)]      = "Ümraniye'den Ankara'ya az eşya veya birkaç kutu göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Konsolide yükle birlikte gönderilen parsiyel eşyalar ekonomik fiyatla zamanında teslim edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü rezervasyon sırasında bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("umraniye", ServisTipi.Ambar)]         = "Ümraniye'deki evi veya ofisi boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli depomuzda kilitli alanda tutulmaktadır. Depolama haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin fiyatına göre bildirilmektedir. Depo kamera ve nem kontrolüyle donatılmıştır.",

        // ── MALTEPE ──
        [("maltepe", ServisTipi.Kamyonet)]      = "Küçükyalı'nın sahil şeridindeki tek yönlü ve dar sokaklar için 3,5 ton kamyonetimiz standart araç tercihimizdir; bina önü duraklama noktası rezervasyon aşamasında kontrol edilmekte ve gerektiğinde kısa süreli kapama koordinasyonu yapılmaktadır. Platform yüksekliğine uygun konumlama ile yükleme süresi minimize edilmektedir.\n\nBağlarbaşı ve Altayçeşme'deki yüksek katlı yapılarda ise asansör koordinasyonuyla büyük mobilyaların çıkarılması verimli planlanmaktadır. Gülensu mahallelerinde geniş anayollar kamyon erişimine de elverdiğinden araç tipi adrese göre belirlenmektedir.",
        [("maltepe", ServisTipi.Sehirlerarasi)] = "Maltepe E-5 üzerinde konumlanmakta ve Ankara güzergâhına direkt bağlantı sağlamaktadır; sabah erken yüklemeyle günün erken saatinde Ankara varışı tamamlanmaktadır. Yükleme planlaması mobilya söküm süresi ve kat adedine göre kişiselleştirilmektedir.\n\nTüm şehirlerarası taşımalarda envanter listesi ve nakliye sigortası standarttır. Maltepe'den Ankara'nın tüm ilçelerine aynı gün kapıdan kapıya teslimat gerçekleştirilmektedir.",
        [("maltepe", ServisTipi.EvdenEve)]      = "Bağlarbaşı ve Altayçeşme'deki çok katlı yapılarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması planlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesi envanter fotoğraflaması yapılmaktadır.\n\nKüçükyalı'daki eski yapılarda kat başına çalışan uzman ekip, büyük mobilyaları merdivenden güvenle çıkarmaktadır. Ankara'daki yeni konuta teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("maltepe", ServisTipi.Ofis)]          = "Maltepe'deki iş yerleri ve küçük-orta ölçekli ofislerin Ankara'ya taşınmasında IT ekipmanı güvenli biçimde paketlenmekte; hafta sonu veya gece taşımayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her ofis taşıması için standart olarak sunulmaktadır. Gece çalışma seçeneği fiyata dahil edilmektedir.",
        [("maltepe", ServisTipi.Fuar)]          = "Maltepe'deki firmalar için Ankara fuar alanlarına stand malzemeleri ve tanıtım gereçleri özel ambalajla hazırlanmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir. Kalkış saati fuar takvimi baz alınarak planlanmaktadır.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("maltepe", ServisTipi.Kamyon)]        = "Gülensu ve Altayçeşme'deki büyük 3+1 ve 4+1 dairelerden Ankara'ya 12 ton kapalı kasalı kamyon ile tek seferlik taşıma, geniş anayollar sayesinde kolay organize edilmektedir. Tüm eşyalar envanter listesiyle belgelenerek sigorta altına alınmaktadır.\n\nYükleme sabah 06:00–06:30 arası başlatılarak E-5 güzergâhından Ankara yoluna girilmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("maltepe", ServisTipi.Parsiyel)]      = "Maltepe'den Ankara'ya birkaç parça mobilya veya kargo kutusu göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Gönderiler haftanın belirli günleri düzenli konsolide sefere dahil edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği mevcuttur.",
        [("maltepe", ServisTipi.Ambar)]         = "Maltepe'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nDepodan çıkışta eşyalar Ankara adresine teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir. Depo kamera ve nem kontrolüyle donatılmıştır.",

        // ── PENDİK ──
        [("pendik", ServisTipi.Kamyonet)]      = "Dolayoba ve Kaynarca'nın büyük konut sitelerinde araç giriş izni ve yükleme noktası önceden site yönetimiyle koordine edilmekte; 3,5 ton kamyonetimiz dar site içi yollarda da manevra yapabilmektedir. Yenişehir'in ticaret bölgelerindeki asansörsüz yapılarda kat başına taşıma planlaması keşifte yapılmaktadır.\n\nKurtköy'ün geniş konut sitelerinde ise yük asansörleri ve büyük araç erişim yolları yüklemeyi hızlandırmaktadır. Pendik'in Kurtköy üzerinden TEM'e bağlantısı sayesinde Ankara güzergâhına kısa sürede çıkılmaktadır.",
        [("pendik", ServisTipi.Sehirlerarasi)] = "Pendik Kurtköy üzerinden TEM'e direkt bağlantısıyla Anadolu yakasının Ankara güzergâhına en kolay çıkılan noktalarından biridir. Sabah 06:30 yüklemesiyle araç trafik yoğunlaşmadan önce İstanbul'u terk etmekte ve aynı gün Ankara varışı tamamlanmaktadır.\n\nTüm şehirlerarası taşımalarda envanter listesi ve nakliye sigortası standarttır. Pendik'ten Ankara'nın tüm ilçelerine aynı gün kapıdan kapıya teslimat gerçekleştirilmektedir.",
        [("pendik", ServisTipi.EvdenEve)]      = "Şeyhli ve Yenişehir'deki yeni asansörlü yapılarda site yönetimiyle yükleme saati koordine edilmekte; büyük mobilyalar söküm-montaj ekibiyle koruyucu ambalajla hazırlanmaktadır. Her eşya taşıma öncesi envanter listesiyle fotoğraflanmaktadır.\n\nDolayoba ve Kaynarca sitelerindeki büyük dairelerden çıkan eşyalar Ankara'ya tek seferlik taşımayla iletilmekte; teslimatta ekip monte ve yerleştirme hizmeti sunmaktadır.",
        [("pendik", ServisTipi.Ofis)]          = "Pendik'teki teknoloji, lojistik ve sanayi firmalarının Ankara'ya kurumsal ofis taşımalarında IT altyapısı güvenli biçimde demonte edilerek taşınmakta; pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir. Hafta sonu taşıma standart seçenektir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşıma paketine dahildir. IT ekipmanı anti-statik ambalajla iletilmektedir.",
        [("pendik", ServisTipi.Fuar)]          = "Pendik'teki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Kurtköy TEM bağlantısı sayesinde kalkış vaktinde esneklik sağlanmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır.",
        [("pendik", ServisTipi.Kamyon)]        = "Kurtköy siteleri ve Kaynarca'daki büyük 3+1–4+1 dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, geniş site yolları ve TEM'e yakın güzergâh sayesinde verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM Kurtköy aksından Ankara güzergâhına girilmektedir. Teslimatta ekip büyük mobilyaları odaya taşımakta ve monte etmektedir.",
        [("pendik", ServisTipi.Parsiyel)]      = "Pendik'ten Ankara'ya birkaç parça eşya, kutu veya tekli mobilya göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Konsolide sefere dahil edilen gönderiler düzenli takvimde Ankara'ya ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği mevcuttur.",
        [("pendik", ServisTipi.Ambar)]         = "Pendik'teki konutunu boşaltıp Ankara'da anahtar bekleyen ya da taşınma tarihi esnek olan müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── KARTAL ──
        [("kartal", ServisTipi.Kamyonet)]      = "Karlıktepe ve Uğur Mumcu'nun dar iç sokaklarında bina önü araç durağı önceden değerlendirilmekte; 3,5 ton kamyonetimiz dar manevra alanlarında sorunsuz yükleme tamamlamaktadır. E-5 üzerindeki geniş arterlere yakın adreslerde ise yükleme noktası seçimi hızlı operasyon sağlamaktadır.\n\nKartal sanayi bölgesinin büyük araç trafiğine alışkın altyapısı, nakliyat araçlarının ilçeyi hızla terk etmesini kolaylaştırmaktadır. E-5 ve TEM Kurtköy güzergâhından Ankara yoluna 15–20 dakikada çıkılmakta; sabah 06:30 kalkışla trafik yoğunluğu aşılmaktadır.",
        [("kartal", ServisTipi.Sehirlerarasi)] = "Kartal'ın E-5 ve TEM Kurtköy bağlantısı, şehirlerarası araçların İstanbul'u hızla terk edip Ankara güzergâhına girmesini sağlamaktadır. Sabah 06:30 yüklemesiyle trafik yoğunlaşmadan önce kalkış yapılmakta; aynı gün Ankara teslimatı standart olarak gerçekleşmektedir.\n\nTüm eşyalar yükleme öncesinde envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Kartal'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("kartal", ServisTipi.EvdenEve)]      = "Soğanlık ve Yakacık'taki çok katlı konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması planlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesi envanter fotoğraflaması yapılmaktadır.\n\nKarlıktepe'nin eski yapılarında asansör yoksa kat başına ekip çalışmakta; büyük mobilyalar merdivenden güvenle çıkarılmaktadır. Ankara'daki yeni adrese varışta monte ve odaya yerleştirme hizmeti kapsamlı paketin parçasıdır.",
        [("kartal", ServisTipi.Ofis)]          = "Kartal'daki sanayi işletmeleri, depolar ve ticari ofislerin Ankara'ya kurumsal taşımalarında IT ekipmanı özel ambalajla güvence altına alınmakta; hafta sonu veya gece taşımayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her ofis taşıması için standart olarak sunulmaktadır. Depo ekipmanı ve büyük sanayi gereçleri için ek araç planlaması yapılmaktadır.",
        [("kartal", ServisTipi.Fuar)]          = "Kartal sanayi bölgesindeki firmalar için Ankara fuar alanlarına taşınan ürünler ve teknik ekipmanlar vibrasyon emici ambalajlarla hazırlanmaktadır. Büyük ve ağır sanayi gereçleri için kamyon, küçük stand malzemeleri için kamyonet seçilmektedir.\n\nFuar açılışından 2 gün önce teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır.",
        [("kartal", ServisTipi.Kamyon)]        = "Soğanlık ve Esentepe'deki büyük 3+1 ve 4+1 dairelerden Ankara'ya 12 ton kapalı kasalı kamyon ile tek seferlik taşıma, E-5 ve TEM güzergâhının avantajını tam olarak kullanmaktadır. Tüm eşyalar sigorta kapsamına alınmakta ve ayrıntılı envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:00–06:30 arası başlatılarak araç güzergâha erken bağlanmaktadır. Ankara'da teslimatta ekip büyük mobilyaları odaya taşımakta ve monte etmektedir.",
        [("kartal", ServisTipi.Parsiyel)]      = "Kartal'dan Ankara'ya birkaç parça mobilya, kargo kutusu veya tekli eşya göndermek için parsiyel araç hizmeti ekonomik ve zamanında teslimat sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği mevcuttur.",
        [("kartal", ServisTipi.Ambar)]         = "Kartal'daki evi veya iş yerini boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nDepodan çıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir. Depo kamera ve nem kontrolüyle donatılmıştır.",

        // ── ATAŞEHİR ──
        [("atasehir", ServisTipi.Kamyonet)]      = "İçerenköy ve Küçükbakkalköy'deki rezidans site girişlerinde araç takip sistemi ve güvenlik geçişi prosedürleri önceden yönetimle koordine edilmekte; 3,5 ton kamyonetimiz belirlenen yükleme noktasına zamanında konumlanmaktadır. Dar manevra alanlarına uyum sağlayan araç boyutu, asansör önüne yakın durma imkânı yaratmaktadır.\n\nFerhatpaşa ve Yenisahra'daki gelişen konut bölgelerinde yeni yapılar yük asansörleriyle donatılmış olmakta; yükleme verimli biçimde planlanabilmektedir. Ataşehir'den Ümraniye aksıyla TEM'e bağlantı çok kısa sürede sağlanmakta; sabah 07:00 öncesi kalkışla Ankara güzergâhına trafiksiz girilmektedir.",
        [("atasehir", ServisTipi.Sehirlerarasi)] = "Ataşehir İstanbul'un Anadolu yakasındaki finans ve yaşam merkezlerinden biri olarak yüksek değerli taşımalara ev sahipliği yapmaktadır. Ümraniye aksından TEM'e bağlantı 10–15 dakikada sağlanmakta; sabah 06:30–07:00 arasında kalkışla günün ortasına kadar Ankara varışı tamamlanmaktadır.\n\nTüm eşyalar yükleme öncesinde ayrıntılı envanter listesiyle fotoğraflanmakta ve sigorta kapsamına alınmaktadır. Kurumsal ve bireysel müşteriler için kapıdan kapıya şehirlerarası nakliyat aynı standart protokolle yürütülmektedir.",
        [("atasehir", ServisTipi.EvdenEve)]      = "Ataşehir'deki modern rezidans sitelerde yük asansörü ön rezervasyonu yönetimle yapılmakta; büyük mobilyaların söküm-montaj süresi keşifte belirlenerek günlük plan hazırlanmaktadır. İçerenköy ve Küçükbakkalköy'deki dairelerden çıkan eşyalar özel ambalajla güvence altına alınmakta ve Ankara adresine hasarsız teslim edilmektedir.\n\nYenisahra'daki villa tipi konutlardan büyük bahçe mobilyalarının taşınmasında kamyon desteği gerektiğinde planlanmaktadır. Ankara'daki teslimatta monte ve yerleştirme hizmeti kapsamlı ev nakliyesi paketine dahildir.",
        [("atasehir", ServisTipi.Ofis)]          = "Ataşehir'deki iş kuleleri, finans firmaları ve teknoloji şirketlerinin Ankara'ya kurumsal taşımalarında iş sürekliliği ön planda tutulmaktadır; taşıma çoğunlukla hafta sonu veya gece saatlerinde gerçekleştirilmekte, Pazartesi sabahı çalışma ortamı hazır olmaktadır. IT altyapısı anti-statik ambalaj ve kablo planı fotoğrafiyle belgelenerek Ankara'da kurulum kolaylaştırılmaktadır.\n\nSunucu, ağ cihazı ve hassas elektronik ekipmanlar özel şoklara karşı koruyucu kasalarda iletilmektedir. Kurumsal fatura, sigorta belgesi ve teslim tutanağı her ofis taşıması için standart olarak sunulmaktadır.",
        [("atasehir", ServisTipi.Fuar)]          = "Ataşehir'deki finans ve teknoloji firmalarının Ankara fuar alanlarına taşınan stand sistemleri ve teknik ekipmanlar vibrasyon emici özel ambalajlarla hazırlanmaktadır. Elektronik display ve sunucu ekipmanı için ESD standartlarına uygun paketleme uygulanmaktadır.\n\nAnkara CNR ve Tüyap alanlarına fuar öncesi 2 gün teslimat taahhüt edilmektedir. Fuar sonrası dönüş taşıması rezervasyonu ilk operasyonla eş zamanlı yapılarak yer garantisi sağlanmaktadır.",
        [("atasehir", ServisTipi.Kamyon)]        = "Ataşehir'in yüksek değerli rezidans dairelerinden Ankara'ya büyük mobilya, ev sinema sistemleri ve lüks eşyaların taşınmasında 12–18 ton kapalı kasalı kamyon kullanılmaktadır. Değerli parçalar için özel köpük kesim ambalaj ve battaniye sarma uygulanmakta; hasar anında tam sigorta devreye girmektedir.\n\nKamyon yüklemesi site yönetimi koordinasyonuyla belirlenen saatte başlatılmakta; araç Ümraniye TEM aksına hızla bağlanmaktadır. Ankara'da teslimatta ekip büyük mobilyaları odaya taşıyıp monte etmektedir.",
        [("atasehir", ServisTipi.Parsiyel)]      = "Ataşehir'den Ankara'ya az eşya veya tekli parça göndermek isteyen bireysel ya da kurumsal müşteriler için parsiyel araç hizmeti ekonomik çözüm sunmaktadır. Düzenli Ankara seferi güzergâhındaki konsolide yüklemeye dahil edilen gönderiler zamanında teslim edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü müşteriye önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği ek ücret karşılığında sunulmaktadır.",
        [("atasehir", ServisTipi.Ambar)]         = "Ataşehir'deki konutunu boşaltıp Ankara'daki yeni adrese geçiş tarihi henüz netleşmemiş müşteriler için eşyalar güvenli depomuzda kilitli alanda tutulmaktadır. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.\n\nDepolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir. Çıkışta eşyalar Ankara adresine ekibimizle teslim edilmektedir.",

        // ── BEYKOZ ──
        [("beykoz", ServisTipi.Kamyonet)]      = "Çubuklu ve Paşabahçe'nin Boğaz kıyısındaki dar ve kıvrımlı sokaklarında büyük araç geçişi mümkün olmadığından 3,5 ton kamyonetimiz standart çözümdür; gerektiğinde ön taşıma ile geniş artere aktarım yapılmaktadır. Riva ve Polonezköy gibi uzak köy noktalarında adres bazlı yol değerlendirmesi rezervasyon aşamasında yapılmaktadır.\n\nBeykoz merkezinden TEM'e Ümraniye–Çekmeköy aksından ulaşılmakta; sabah erken kalkışla Boğaz güzergâhındaki trafik sıkışıklığı aşılmaktadır. Uzak mahalleler nedeniyle yükleme saati özellikle önem taşımakta; 06:00–06:30 başlangıç önerilmektedir.",
        [("beykoz", ServisTipi.Sehirlerarasi)] = "Beykoz'dan şehirlerarası taşımalarda araç Ümraniye–Çekmeköy aksından TEM'e bağlanmakta; sabah erken yüklemeyle İstanbul trafiğine girmeden Ankara güzergâhına girilmektedir. İlçenin uzak konumu gözetilerek yükleme saati önceden kişiselleştirilmektedir.\n\nTüm eşyalar envanter listesiyle kayıt altına alınmakta ve nakliye sigortasıyla güvence altına alınmaktadır. Beykoz'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("beykoz", ServisTipi.EvdenEve)]      = "Beykoz Merkez ve Anadoluhisarı'nın çok katlı yapılarında asansör koordinasyonu ve söküm-montaj ekibiyle kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunarak Ankara yoluna hazırlanmaktadır.\n\nRiva ve Polonezköy'deki müstakil ev ve köy konutlarında kamyonet ile daha küçük araç kombinasyonu gerektiğinde planlanmaktadır. Ankara'daki yeni adrese teslimatta ekip monte ve odaya yerleştirme hizmeti sunmaktadır.",
        [("beykoz", ServisTipi.Ofis)]          = "Beykoz'daki işletmeler ve küçük ölçekli ofislerin Ankara'ya kurumsal taşımalarında IT ekipmanı güvenli ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği sağlanmaktadır. Kurumsal fatura ve sigorta belgesi standart olarak sunulmaktadır.\n\nGüvenli arşiv nakliyesi için belgeler kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir.",
        [("beykoz", ServisTipi.Fuar)]          = "Beykoz'daki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve promosyon materyalleri darbe emici ambalajlarla hazırlanmaktadır. Fuar takvimi ve kurulum günü baz alınarak kalkış planı yapılmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma için aynı ambalaj standardı uygulanmaktadır.",
        [("beykoz", ServisTipi.Kamyon)]        = "Paşabahçe ve Çubuklu'daki büyük konutlardan Ankara'ya değerli mobilya ve büyük ev eşyaları 12–18 ton kapalı kasalı kamyon ile sigortalı taşınmaktadır. Boğaz kıyısındaki dar sokaklarda gerekliyse kamyonet aktarması yapılarak eşyalar geniş artere taşınır, oradan kamyona yüklenir.\n\nTüm eşyalar hareket öncesinde envanter fotoğrafıyla belgelenmekte; sigorta poliçesi yükleme başlamadan aktive edilmektedir.",
        [("beykoz", ServisTipi.Parsiyel)]      = "Beykoz'dan Ankara'ya birkaç parça eşya veya kargo göndermek için parsiyel araç hizmeti ekonomik çözüm sunmaktadır. Gönderiler Ankara yönlü konsolide sefere dahil edilmekte; ağırlık ve hacme göre fiyatlandırılmaktadır.\n\nToplama adresinden Ankara teslim noktasına kadar 1–2 iş günü süre öngörülmekte; teslimat günü önceden bildirilmektedir.",
        [("beykoz", ServisTipi.Ambar)]         = "Beykoz'daki evi boşaltırken Ankara'daki yeni konuta geçiş tarihi bekleniyor ise eşyalar güvenli depomuzda kilitli alanda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── ÇEKMEKÖY ──
        [("cekmekoy", ServisTipi.Kamyonet)]      = "Nişantepe ve Hamidiye'nin yeşil ve sakin mahallelerindeki müstakil ev ve villa taşımalarında 3,5 ton kamyonetimiz dar yol ağına uyum sağlamaktadır. Site girişlerinde yönetim koordinasyonuyla yükleme noktası önceden belirlenmekte; operasyon gününde sürpriz yaşanmamaktadır.\n\nMehmet Akif ve Çekmeköy Merkez'deki apartman bloklarında ise geniş bina girişleri ve asansörler yüklemeyi verimli kılmaktadır. TEM'e Ümraniye–Çekmeköy güzergâhından bağlantı sağlanmakta; sabah 06:30 kalkışla Ümraniye kavşağı geçildikten sonra yol açık akmaktadır.",
        [("cekmekoy", ServisTipi.Sehirlerarasi)] = "Çekmeköy'den şehirlerarası araçlar Ümraniye aksıyla TEM'e hızla bağlanmakta; sabah yüklemesiyle gün içinde Ankara varışı tamamlanmaktadır. İlçenin sakin dokusu sayesinde araç çıkışı büyük şehir ilçelerine kıyasla daha akıcı gerçekleşmektedir.\n\nTüm eşyalar envanter listesiyle kayıt altına alınmakta ve nakliye sigortasına dahil edilmektedir. Çekmeköy'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("cekmekoy", ServisTipi.EvdenEve)]      = "Mehmet Akif ve Çekmeköy Merkez'deki apartmanlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya koruyucu ambalajla güvence altına alınmakta; taşıma öncesi envanter fotoğraflaması yapılmaktadır.\n\nTaşdelen ve Nişantepe'deki müstakil konutlarda büyük bahçe mobilyaları ve villa eşyaları için ekip ve araç planlaması ayrıca yapılmaktadır. Ankara'da teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("cekmekoy", ServisTipi.Ofis)]          = "Çekmeköy'deki küçük ve orta ölçekli işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı ofis çalışmaya hazır teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura ve sigorta belgesi her taşımada standarttır.",
        [("cekmekoy", ServisTipi.Fuar)]          = "Çekmeköy'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve promosyon materyalleri darbe emici ambalajlarla hazırlanmaktadır. Fuar takvimi baz alınarak kalkış planı yapılmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır.",
        [("cekmekoy", ServisTipi.Kamyon)]        = "Taşdelen ve Nişantepe'deki müstakil ve villa tipi konutlardan Ankara'ya büyük mobilya ve villa eşyaları 12–18 ton kapalı kasalı kamyon ile tek seferlik sigortalı taşınmaktadır. Değerli mobilyalar için özel köpük kesim ambalaj uygulanmaktadır.\n\nYükleme sabah erkenden başlatılarak TEM'e Ümraniye aksından bağlanılmaktadır. Ankara'da teslimatta ekip büyük mobilyaları odaya taşımakta ve monte etmektedir.",
        [("cekmekoy", ServisTipi.Parsiyel)]      = "Çekmeköy'den Ankara'ya birkaç parça mobilya, kutu veya tekli eşya göndermek için parsiyel araç hizmeti ekonomik çözüm sunmaktadır. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.",
        [("cekmekoy", ServisTipi.Ambar)]         = "Çekmeköy'deki evi boşaltıp Ankara'da anahtar bekleyen ya da taşınma tarihi esnek olan müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── SANCAKTEPE ──
        [("sancaktepe", ServisTipi.Kamyonet)]      = "Veysel Karani ve Fatih mahallelerindeki yeni konut sitelerinde 3,5 ton kamyonetimiz geniş bina girişleri ve asansörlü yapılar sayesinde verimli yükleme tamamlamaktadır. Site girişleri ve araç park noktaları önceden yönetimle koordine edilmektedir.\n\nSancaktepe'nin hızla gelişen konut dokusu büyük araç erişimine de elverişli olmakta; TEM'e Ümraniye–Kartal aksından sabah trafiği öncesinde bağlanılmaktadır.",
        [("sancaktepe", ServisTipi.Sehirlerarasi)] = "Sancaktepe'den şehirlerarası araçlar Ümraniye aksıyla TEM'e bağlanmakta; sabah 06:30 yüklemesiyle trafik yoğunlaşmadan Ankara güzergâhına girilmektedir. İlçenin TEM'e yakınlığı teslim süresini kısaltmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Sancaktepe'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("sancaktepe", ServisTipi.EvdenEve)]      = "Sancaktepe Merkez ve Kaynarca'daki konut sitelerinde asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması planlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmaktadır.\n\nEyüp Sultan ve Fatih mahallelerinin eski yapılarında kat başına ekip planlaması yapılmakta; büyük mobilyalar güvenle çıkarılmaktadır. Ankara'da teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("sancaktepe", ServisTipi.Ofis)]          = "Sancaktepe'deki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı özel ambalajla güvence altına alınmakta; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("sancaktepe", ServisTipi.Fuar)]          = "Sancaktepe'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Fuar takvimi baz alınarak kalkış planı yapılmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır.",
        [("sancaktepe", ServisTipi.Kamyon)]        = "Sancaktepe'deki 3+1 ve büyük dairelerden Ankara'ya 12 ton kapalı kasalı kamyon ile tek seferlik taşıma, TEM'e yakın güzergâh avantajıyla verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah erken başlatılmakta; Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("sancaktepe", ServisTipi.Parsiyel)]      = "Sancaktepe'den Ankara'ya birkaç parça mobilya veya kargo kutusu göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; kırılgan parçalar için ek ambalaj seçeneği mevcuttur.",
        [("sancaktepe", ServisTipi.Ambar)]         = "Sancaktepe'deki evi boşaltıp Ankara'da anahtar bekleyen ya da taşınma tarihi esnek olan müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmektedir.",

        // ── SULTANBEYLİ ──
        [("sultanbeyli", ServisTipi.Kamyonet)]      = "Sultanbeyli'nin yoğun konut dokusundaki bazı dar iç sokaklar için 3,5 ton kamyonetimiz bina girişine en yakın noktaya konumlanmakta; kat başına taşıma ekibi hızlı yükleme sağlamaktadır. Mehmet Akif ve Battalpasa mahallelerinde asansörsüz yapılarda söküm-montaj ekibi önceden planlanmaktadır.\n\nSultan Orhan ve Hürriyet mahallelerindeki yeni konut bloklarında ise asansör koordinasyonuyla verimli yükleme yapılmaktadır. Sultanbeyli'den Kartal–Kurtköy aksıyla TEM'e sabah 07:00 öncesi bağlanılarak Ankara güzergâhına girilmektedir.",
        [("sultanbeyli", ServisTipi.Sehirlerarasi)] = "Sultanbeyli'den şehirlerarası araçlar Kartal aksıyla E-5 ve TEM Kurtköy güzergâhından Ankara yoluna çıkmakta; sabah 06:30 yüklemesiyle aynı gün teslimat tamamlanmaktadır. İlçenin yüksek nüfus yoğunluğu nedeniyle erken kalkış özellikle önem taşımaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Sultanbeyli'den Ankara'nın tüm ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("sultanbeyli", ServisTipi.EvdenEve)]      = "Mehmet Akif ve İnönü mahallelerindeki yüksek katlı yapılarda asansör ön rezervasyonu ve komşu koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmaktadır.\n\nBüyük 3+1 ve 4+1 dairelerdeki çok parçalı mobilya takımları söküm-montaj ekibiyle parçalara ayrılmakta; Ankara'daki yeni adrese varışta monte edilmektedir.",
        [("sultanbeyli", ServisTipi.Ofis)]          = "Sultanbeyli'deki küçük ve orta ölçekli işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı güvenli ambalajla paketlenmekte; hafta sonu taşımayla iş sürekliliği korunmaktadır. Kurumsal fatura ve sigorta belgesi standart olarak sunulmaktadır.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir.",
        [("sultanbeyli", ServisTipi.Fuar)]          = "Sultanbeyli'deki işletmeler için Ankara fuar alanlarına taşınan stand sistemleri ve ürün materyalleri darbe emici ambalajlarla hazırlanmaktadır. Fuar takvimi baz alınarak kalkış planı yapılmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma için aynı operasyon ekibi temin edilmektedir.",
        [("sultanbeyli", ServisTipi.Kamyon)]        = "Sultanbeyli'deki büyük 3+1 dairelerden Ankara'ya 12 ton kapalı kasalı kamyon ile tek seferlik taşıma, birden fazla kamyonet seferine kıyasla hem daha ekonomik hem daha güvenlidir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah erken başlatılarak Kartal–TEM Kurtköy güzergâhından Ankara yoluna girilmektedir. Teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("sultanbeyli", ServisTipi.Parsiyel)]      = "Sultanbeyli'den Ankara'ya az eşya veya birkaç kutu göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Konsolide yükle birlikte gönderilen eşyalar ekonomik fiyatla zamanında teslim edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü rezervasyon sırasında bildirilmektedir.",
        [("sultanbeyli", ServisTipi.Ambar)]         = "Sultanbeyli'deki evi boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── TUZLA ──
        [("tuzla", ServisTipi.Kamyonet)]      = "Aydınlı ve Postane mahallelerindeki konut bölgelerine 3,5 ton kamyonetimiz sorunsuz erişmekte; OSB'ye alışkın ekip hızlı yükleme planlaması yapmaktadır. İçmeler sahil şeridindeki konutlarda dar yollar için adres bazlı araç değerlendirmesi yapılmaktadır.\n\nTuzla'nın D-100 ve TEM Kurtköy bağlantısı, yükleme sonrası araçların Ankara güzergâhına en hızlı şekilde girmesini sağlamaktadır. Sabah 06:30 kalkışla gün içinde Ankara varışı rahatlıkla tamamlanmaktadır.",
        [("tuzla", ServisTipi.Sehirlerarasi)] = "Tuzla'nın D-100 ve TEM Kurtköy bağlantısı sayesinde şehirlerarası araçlar Ankara yoluna İstanbul'un en doğu noktasından hızla çıkmaktadır. Sabah 06:30–07:00 yüklemesiyle aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Tuzla'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("tuzla", ServisTipi.EvdenEve)]      = "İçmeler ve Mimar Sinan'daki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması yapılmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmaktadır.\n\nOSB bölgesine alışkın sanayi altyapısı ve geniş yollar büyük mobilyaların taşınmasını kolaylaştırmaktadır. Ankara'da teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("tuzla", ServisTipi.Ofis)]          = "Tuzla OSB'deki firmalar ve İçmeler'deki kurumsal ofislerin Ankara'ya taşınmasında IT ekipmanı anti-statik ambalajla, sunucu ve ağ cihazları özel koruyucu kasalarla paketlenmektedir. Hassas sanayi ekipmanı için ESD standartlarına uygun ambalaj uygulanmaktadır.\n\nHafta sonu veya gece taşımayla iş sürekliliği korunmakta; kurumsal fatura ve sigorta belgesi standart olarak sunulmaktadır.",
        [("tuzla", ServisTipi.Fuar)]          = "Tuzla sanayi bölgesindeki firmalar için Ankara fuar alanlarına taşınan ürünler ve teknik ekipmanlar vibrasyon emici ambalajlarla güvence altına alınmaktadır. Büyük ve ağır sanayi ekipmanı için kamyon tercih edilmekte; küçük stand malzemeleri için kamyonet yeterli olmaktadır.\n\nFuar açılışından 2 gün önce teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma rezervasyonu önceden alınabilmektedir.",
        [("tuzla", ServisTipi.Kamyon)]        = "Tuzla'daki sanayi tesisleri veya büyük konutlardan Ankara'ya 12–18 ton kamyon ile tek seferlik taşıma, büyük araç altyapısına alışkın D-100 ve TEM güzergâhından geçmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah erken başlatılmakta; Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("tuzla", ServisTipi.Parsiyel)]      = "Tuzla'dan Ankara'ya birkaç parça mobilya, kargo veya sanayi malzemesi göndermek için parsiyel araç hizmeti ekonomik ve zamanında teslimat sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.",
        [("tuzla", ServisTipi.Ambar)]         = "Tuzla'daki evi veya iş yerini boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── ŞİLE ──
        [("sile", ServisTipi.Kamyonet)]      = "Şile Merkez ve Ağva mahallelerindeki kalıcı konutlara 3,5 ton kamyonetimiz sorunsuz erişmektedir. Uzak güzergâh nedeniyle bina önü duraklama noktası önceden belirlenmekte; yükleme 06:00'da başlatılarak araç sabahın erken saatinde İstanbul ana güzergâhına yönlenmektedir.\n\nKöy yollarındaki bazı noktalarda kamyonet boyutu tercih edilmekte; ana yola çıkıldığında E-80 Kurtköy güzergâhından Ümraniye üzerinden TEM'e bağlanılmaktadır. Ankara'ya aynı gün teslimat uzun güzergâha karşın erken kalkışla sağlanmaktadır.",
        [("sile", ServisTipi.Sehirlerarasi)] = "Şile İstanbul'un Karadeniz kıyısındaki en uzak ilçelerinden biri olduğundan şehirlerarası taşımalarda sabah 05:30–06:00 arası yükleme başlatılmaktadır. E-80 Kurtköy güzergâhıyla Ümraniye'ye, oradan TEM'e bağlanan araç gün içinde Ankara teslimatını tamamlamaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Uzun güzergâh nedeniyle rezervasyon aşamasında kalkış saati ve yükleme süresi birlikte planlanmaktadır.",
        [("sile", ServisTipi.EvdenEve)]      = "Şile'deki yazlık ve müstakil konutlardan Ankara'ya kapıdan kapıya ev taşıması için yükleme planlaması 06:00 gibi başlatılmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesi envanter fotoğraflaması yapılmaktadır.\n\nKıyı kesimindeki bazı dar yollarda kamyonet tercih edilmekte; büyük mobilyalar söküm-montaj ekibiyle güvenle çıkarılmaktadır. Ankara'da teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("sile", ServisTipi.Ofis)]          = "Şile'deki küçük işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı güvenli ambalajla paketlenmekte; uzun güzergâh gözetilerek sabah erken kalkış planlanmaktadır. Kurumsal fatura ve sigorta belgesi standart olarak sunulmaktadır.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir.",
        [("sile", ServisTipi.Fuar)]          = "Şile'deki firmalar için Ankara fuar taşımalarında uzun güzergâh nedeniyle kalkış günü bir gün öne alınmakta; fuar kurulum tarihinden 3 gün önce teslimat taahhüt edilmektedir. Stand ve ekipmanlar darbe emici ambalajlarla güvence altına alınmaktadır.\n\nFuar sonrası geri taşıma rezervasyonu ilk operasyonla birlikte alınmaktadır.",
        [("sile", ServisTipi.Kamyon)]        = "Şile'deki büyük yazlık veya müstakil konutlardan Ankara'ya 12 ton kapalı kasalı kamyon ile tek seferlik sigortalı taşıma yapılmaktadır. Uzun güzergâh nedeniyle sabah 05:30 kalkış hedeflenmekte; tüm eşyalar hareket öncesinde envanter fotoğrafıyla belgelenmektedir.\n\nAnkara'da teslimatta ekip büyük mobilyaları odaya taşımakta ve monte etmektedir.",
        [("sile", ServisTipi.Parsiyel)]      = "Şile'den Ankara'ya az eşya veya kargo göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Uzak mesafe fiyatlandırmaya yansıtılmakta; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; gönderim günü önceden bildirilmektedir.",
        [("sile", ServisTipi.Ambar)]         = "Şile'deki evi veya yazlık konutu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── ADALAR ──
        [("adalar", ServisTipi.Kamyonet)]      = "Büyükada, Heybeliada ve Burgazada'da motorlu araç girişi yasak olduğundan eşyalar önce iskeleye fayton ya da belediye aracıyla taşınmakta; ardından kamyonetimiz Kadıköy veya Pendik iskelesinde teslim alarak kara güzergâhına devam etmektedir. Bu transfer süreci rezervasyon aşamasında adım adım planlanmaktadır.\n\nKara bağlantısına geçildikten sonra Ümraniye–TEM aksından Ankara güzergâhına girilmektedir. İskele saatlerine bağlı kalkış planlaması erken rezervasyon gerektirmektedir.",
        [("adalar", ServisTipi.Sehirlerarasi)] = "Adalar'dan Ankara'ya şehirlerarası taşımada iskele–kara transfer koordinasyonu önceden planlanmaktadır; eşyalar Kadıköy veya Pendik iskelesinde kamyona aktarılmakta ve aynı gün Ankara teslimatı hedeflenmektedir. İskele saatlerine göre kalkış zamanı müşteriyle birlikte belirlenmektedir.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Transfer dahil toplam süre standart ilçelere kıyasla 2–3 saat daha uzun planlanmaktadır.",
        [("adalar", ServisTipi.EvdenEve)]      = "Büyükada ve Heybeliada'daki konutlardan ev taşımasında iskele koordinasyonu, ada içi taşıma planlaması ve kara transferi kapsamlı biçimde organize edilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunarak iskeleye taşınmaktadır.\n\nKadıköy veya Pendik iskelesinden kamyona yüklenen eşyalar Ankara'ya aynı gün teslim edilmektedir. Teslimatta ekip monte ve odaya yerleştirme hizmeti sunmaktadır.",
        [("adalar", ServisTipi.Ofis)]          = "Adalardaki otel, restoran veya küçük işletmelerin Ankara'ya kurumsal taşımalarında iskele–kara bağlantısı dahil planlama yapılmakta; IT ekipmanı özel ambalajla korunmaktadır. Uzun transfer süreci gözetilerek gün öncesinden kalkış planlaması yapılmaktadır.\n\nKurumsal fatura ve sigorta belgesi standart olarak sunulmaktadır.",
        [("adalar", ServisTipi.Fuar)]          = "Adalardaki işletmeler için Ankara fuar taşımalarında iskele transfer günü hesaba katılarak kalkış fuar açılışından en az 3 gün öncesine alınmaktadır. Stand materyalleri darbe emici ambalajlarla korunmaktadır.\n\nRezervasyon en az 5 iş günü öncesinden alınmakta; fuar sonrası geri taşıma da aynı planlama süreciyle organize edilmektedir.",
        [("adalar", ServisTipi.Kamyon)]        = "Adalardaki büyük konut veya otel eşyaları için kamyon, Kadıköy veya Pendik iskelesinde iskele transferi tamamlandıktan sonra yüklenerek Ankara güzergâhına hareket etmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nİskele saati ve kamyon kalkış zamanı koordineli planlanmakta; Ankara'da teslimatta ekip büyük mobilyaları odaya taşımaktadır.",
        [("adalar", ServisTipi.Parsiyel)]      = "Adalardaki konutlardan Ankara'ya birkaç parça eşya veya kargo göndermek için iskele transferi dahil parsiyel araç hizmeti koordineli biçimde sunulmaktadır. Ada içi fayton veya yük arabası planlaması ayrıca organize edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; toplam transfer ve teslimat süresi önceden bildirilmektedir.",
        [("adalar", ServisTipi.Ambar)]         = "Adalardaki konut boşaltmasında eşyalar iskele transferiyle karaya alınarak güvenli depomuzda kilitli alanda muhafaza edilmektedir. Ankara'ya taşınma gününe kadar eşyalar depoda güvenle beklemektedir.\n\nDepodan çıkışta eşyalar Ankara adresine ekibimizle teslim edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.",

        // ── ŞİŞLİ ──
        [("sisli", ServisTipi.Kamyonet)]      = "Nişantaşı ve Kurtuluş'un arka sokaklarında park yeri kısıtı ve dar geçişler nedeniyle 3,5 ton kamyonet standart çözüm olmaktadır; bina girişine en yakın konuma araç alınarak hızlı yükleme gerçekleştirilmektedir. Sabah 06:30 öncesi ya da gece geç saatlerde yükleme, Nişantaşı'nın yoğun araç trafiğini en aza indirgemektedir.\n\nBomonti'nin yenilenen konut bloklarında ve Cumhuriyet Caddesi'ndeki modern yapılarda geniş bina girişleri büyük mobilyaların sorunsuz çıkarılmasına imkân tanımaktadır. Mecidiyeköy'deki ticaret ve iş yoğunluğu gözetilerek araç çıkış saati Zincirlikuyu kavşağının en az yoğun dilimi için planlanmaktadır.",
        [("sisli", ServisTipi.Sehirlerarasi)] = "Şişli'den şehirlerarası araçlar Zincirlikuyu–TEM aksı ya da Maslak bağlantısından Ankara yoluna çıkmakta; sabah mesai başlamadan önce kalkışla günün erken saatinde Ankara'ya varılmaktadır. Her rezervasyonda trafik verilerine dayalı kalkış saati önerilmekte; bu sayede Boğaz köprüsü gecikmelerinden kaçınılmaktadır.\n\nTüm eşyalar yükleme öncesinde sigorta kapsamına alınmakta; değerli ve kırılgan parçalar için ek ambalaj ve sigorta ek teminatı teklif edilmektedir. Ankara'nın her ilçesine aynı gün kapıdan kapıya teslimat sağlanmaktadır.",
        [("sisli", ServisTipi.EvdenEve)]      = "Nişantaşı'nın asansörsüz ya da dar asansörlü tarihi apartmanlarında büyük mobilyalar söküm-montaj ekibi tarafından parçalara ayrılarak merdivenden taşınmakta; battaniye ve balonlu naylon ambalajla her parça korunmaktadır. Kat başına iş süresi keşif aşamasında netleştirilmekte; fazla zaman ya da ekip ihtiyacı önceden fiyatlandırılmaktadır.\n\nBomonti ve Mecidiyeköy'deki yeni konut projelerinde ise yük asansörü planlamasıyla yükleme verimli biçimde tamamlanmakta; Ankara'daki yeni adrese varışta monte edilerek müşteri aynı gün yerleşebilmektedir.",
        [("sisli", ServisTipi.Ofis)]          = "Mecidiyeköy ve Şişli'deki iş kuleleri ile finans merkezlerinin Ankara'ya kurumsal taşımalarında gece ya da hafta sonu nakliyat tercih edilmekte; pazartesi sabahı personelin çalışmaya hazır ofiste başlaması hedeflenmektedir. IT ekipmanı anti-statik ambalaj, sunucular özel kasa ve kablo planı fotoğrafıyla belgelenerek iletilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi standart olarak sunulmaktadır.",
        [("sisli", ServisTipi.Fuar)]          = "Şişli'deki reklam, medya ve teknoloji firmalarının Ankara fuar alanlarına gönderilen stand sistemleri, display paneller ve promosyon materyalleri darbe emici ambalajlarla korunmaktadır. Grafik baskılar rulo koliler içinde; ekranlar özel köpük kesim kasalarda iletilmektedir.\n\nAnkara CNR ve Tüyap fuar açılışından 2 iş günü önce teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma için aynı operasyon saatlerinde araç temin edilmekte; hasarlı iade durumunda sigorta tutanağı tutulmaktadır.",
        [("sisli", ServisTipi.Kamyon)]        = "Mecidiyeköy ve Harbiye'deki 3+1–4+1 büyük dairelerden Ankara'ya taşımalarda 12 ton kapalı kasalı kamyon tek seferlik idealdir; Nişantaşı'nın değerli mobilya ve antikalarını tek araçta konsolide ederek ek sefer maliyetinden kaçınılmaktadır. Yükleme saati Cumhuriyet Caddesi trafiğinin en sakin dilimine denk getirilmektedir.\n\nTüm eşyalar yola çıkmadan önce envanter fotoğrafıyla belgelenerek sigorta altına alınmaktadır. Ankara'ya varışta ekip eşyaları odaya taşımakta; büyük mobilyaları monte etmektedir.",
        [("sisli", ServisTipi.Parsiyel)]      = "Şişli'den Ankara'ya birkaç parça mobilya, kargo kutusu veya ofis malzemesi göndermek için parsiyel araç hizmeti, tam araç kirasının çok altında ekonomik çözüm sunar. Gönderiler haftanın belirli günleri Ankara güzergâhındaki konsolide sefere dahil edilmektedir.\n\nGönderinin hacim ve ağırlığına göre fiyat belirlenmekte; toplama ve teslim adresleri belgeye yazılmaktadır. Kırılgan parçalar için balonlu naylon ambalaj eklenerek güvenli iletim sağlanmaktadır.",
        [("sisli", ServisTipi.Ambar)]         = "Şişli'deki konutunu boşaltıp Ankara'daki yeni ev teslimini bekleyen müşteriler için eşyalar güvenli depomuzda kilitli, kontrollü alanda tutulmaktadır. Depolama süresi haftalık ve aylık dönemler hâlinde esnek biçimde planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine taşınmakta; taşıma ücreti o tarihin tarife fiyatına göre önceden bildirilmektedir. Depo tesisi kamera sistemi ve nem kontrol ekipmanıyla donatılmıştır.",

        // ── BEŞİKTAŞ ──
        [("besiktas", ServisTipi.Kamyonet)]      = "Bebek ve Arnavutköy'ün taş kaplı Boğaz kıyısı sokaklarında büyük araç geçişi kısıtlı olmakta; 3,5 ton kamyonetimiz bina girişine en yakın noktaya konumlarak kısa mesafeli taşıma yapmaktadır. Ortaköy'deki bazı yalı ve köşk adreslerinde ise eşyalar kamyonete aktarılmadan önce ön taşımayla toplanmaktadır.\n\nLevent ve Balmumcu'daki modern iş ve konut yapılarında ise geniş bina girişleri ve yük asansörleri yüklemeyi kolaylaştırmaktadır. Beşiktaş merkezi sabah mesai öncesinde araç yoğunluğu yüksek olduğundan yükleme 06:00–06:30 arasında başlatılmakta; Maslak aksına ulaşıldığında TEM'e bağlantı hızla gerçekleşmektedir.",
        [("besiktas", ServisTipi.Sehirlerarasi)] = "Beşiktaş'tan şehirlerarası taşımalarda araç Maslak aksıyla TEM'e yönlendirilerek Boğaz geçiş süresi minimize edilmektedir; sabah mesai başlamadan kalkışla gün içinde Ankara teslimatı tamamlanmaktadır. Yükleme saati ve güzergâh, Boğaz köprüsü saatlik trafik verilerine göre her rezervasyonda ayrıca planlanmaktadır.\n\nÇok değerli mobilya ve antika içeren Bebek ve Etiler dairelerinde yükleme öncesinde detaylı hasar-öncesi fotoğraflama protokolü uygulanmakta; sigorta kapsamı müşteriye yazılı olarak teyit edilmektedir. Ankara'ya varışta adres bildirimi yapıldığında araç gün içinde konumlanmakta ve taşıma tamamlanmaktadır.",
        [("besiktas", ServisTipi.EvdenEve)]      = "Levent ve Etiler'deki modern rezidanslarda yük asansörü planlaması ve komşu koordinasyonuyla büyük mobilyalar hasarsız indirilmekte; tüm eşyalar koruyucu ambalajla Ankara yoluna çıkmaktadır. Beşiktaş'ın yeni yapı stoğundaki konutlarda mobilya söküm ve montaj da kapsamlı ev taşıması paketine dahildir.\n\nOrtaköy ve Arnavutköy'deki tarihi yapılarda ise asansör olmadığından ekip kat kat taşıma planlaması yapmakta; koltuk ve büyük dolaplar için montaj söküm yapılarak merdivenlerden güvenle çıkarılmaktadır. Ankara'daki yeni konuta teslimatta aynı ekip monte ederek müşterinin yerleşmesini kolaylaştırmaktadır.",
        [("besiktas", ServisTipi.Ofis)]          = "Levent ve Balmumcu'daki finans kuruluşları, hukuk büroları ve holding genel müdürlüklerinin Ankara'ya kurumsal ofis taşımalarında IT altyapısı güvenlik protokolüne göre demonte edilmekte; sunucu rafları, UPS cihazları ve ağ ekipmanı özel kasa ile paketlenmektedir. Kablolama planı fotoğraflanmakta; Ankara'da aynı düzene monte edilmektedir.\n\nTaşıma çoğunlukla iş saatleri sonrasında ya da hafta sonu gerçekleştirilmekte; Pazartesi sabahı personel çalışmaya hazır ofiste başlamaktadır. Tüm kurumsal taşımalarda sigorta belgesi, yük envanteri ve teslimat tutanağı standart olarak düzenlenmektedir.",
        [("besiktas", ServisTipi.Fuar)]          = "Beşiktaş'taki kurumsal firmalar ve marka ajanslarının Ankara fuar alanlarına taşınan stand sistemleri, ürün showroom'ları ve tanıtım ekipmanları darbe emici ambalajlarla güvence altına alınmaktadır. Stand ölçü ve ağırlıklarına göre araç tipi seçilmekte; büyük yapılarda kamyon, küçük stand malzemeleri için kamyonet kullanılmaktadır.\n\nAnkara CNR ve Tüyap alanlarına fuar açılışından 2 gün önce teslimat garanti edilmektedir. Fuar sonrası iade taşımasında da aynı ambalaj standartları uygulanmakta; hasarlı iade varsa tutanak tutulmaktadır.",
        [("besiktas", ServisTipi.Kamyon)]        = "Etiler ve Levent'teki 3+1–4+1 büyük daireler ile Bebek köşklerinden Ankara'ya büyük mobilya ve ev eşyası taşımalarında 12–18 ton kapalı kasalı kamyon tercih edilmektedir. Değerli mobilyalar için özel köpük ve battaniye ambalajı uygulanmakta; antika ve cam parçalar ayrı kasalara yerleştirilmektedir.\n\nYükleme sabah 06:00'da başlatılarak araç Maslak aksından TEM'e yönlenmekte; trafik yoğunluğu olmadan Ankara güzergâhına girilmektedir. Kamyon nakliyesi öncesinde her eşya envanter fotoğrafıyla belgelenmekte; sigorta poliçesi yükleme başlamadan önce aktive edilmektedir.",
        [("besiktas", ServisTipi.Parsiyel)]      = "Beşiktaş'tan Ankara'ya az sayıda parça, tekli mobilya veya ofis kargo kutusu göndermek isteyen müşteriler için parsiyel araç hizmeti, tam araç kiralamanın çok altında maliyet sunmaktadır. Gönderiler diğer parsiyel yüklerle güvenli biçimde birleştirilmekte ve Ankara güzergâhındaki düzenli sefere dahil edilmektedir.\n\nParsiyel fiyatlandırma ağırlık ve hacme göre yapılmakta; toplama adresinden Ankara teslim noktasına kadar takip hizmeti sunulmaktadır. Kırılgan parçalar için özel ambalaj seçeneği ek ücret karşılığında sağlanmaktadır.",
        [("besiktas", ServisTipi.Ambar)]         = "Beşiktaş'taki konutunu boşaltıp Ankara'da henüz anahtar alamayan veya yeni konuta geçiş tarihi belirsiz olan müşteriler için eşyalar güvenli depomuzda mühürlü alanda tutulmaktadır. Depo giriş-çıkışları kayıt altına alınmakta; müşteri dilediği zaman önceden bildirerek eşyalarına erişebilmektedir.\n\nDepolama süresi haftalık ya da aylık olarak esnek biçimde planlanabilmektedir. Çıkışta eşyalar Ankara adresine taşınmakta; taşıma ücreti o tarihin fiyat listesine göre hesaplanmaktadır.",

        // ── BAKIRKÖY ──
        [("bakirkoy", ServisTipi.Kamyonet)]      = "Zuhuratbaba ve Cevizlik'teki eski apartmanlarda asansör bulunmaması durumunda 3,5 ton kamyonetimiz bina girişine yakın konumlanmakta ve kat başına taşıma ekibi koordinasyonuyla yükleme tamamlanmaktadır. Bazı dar sokak ve çıkmaz yollar için adres bazlı manevra değerlendirmesi rezervasyon aşamasında yapılmaktadır.\n\nAtaköy ve Florya'daki büyük site girişlerinde ise geniş yollar kamyon erişimine de elvermekte; kamyonet bu bölgelerde yükleme hızını optimize etmek amacıyla tercih edilmektedir. Bakırköy'den E-5 güzergâhına direkt bağlantıyla Ankara yoluna kısa sürede çıkılmaktadır.",
        [("bakirkoy", ServisTipi.Sehirlerarasi)] = "Bakırköy E-5 üzerinde konumlanması nedeniyle şehirlerarası araçların Ankara güzergâhına en kolay bağlandığı Avrupa yakası ilçelerinden biridir. Sabah 06:30–07:00 arası yüklemeyle güzergâh araç yoğunluğu artmadan Ankara yoluna girilmektedir.\n\nTüm şehirlerarası taşımalarda envanter listesi ve nakliye sigortası standart olarak sunulmaktadır. Bakırköy'den Ankara'nın tüm ilçelerine aynı gün kapıdan kapıya teslimat gerçekleştirilmektedir.",
        [("bakirkoy", ServisTipi.EvdenEve)]      = "Ataköy'ün büyük sitelerinde site yönetimi koordinasyonuyla yükleme saati ve asansör ön rezervasyonu yapılmakta; büyük mobilyaların hasarsız çıkarılması için söküm-montaj ekibi önceden organize edilmektedir. Her eşya battaniye ve balonlu naylon ambalajıyla korunmaktadır.\n\nFlorya'nın köklü konut dokusundaki asansörsüz yapılarda kat başına ekip çalışmakta; ağır beyaz eşya ve büyük dolap sistemleri için ek taşıma ekipmanı kullanılmaktadır. Ankara'daki yeni adrese varışta monte ve odaya yerleştirme hizmeti dahildir.",
        [("bakirkoy", ServisTipi.Ofis)]          = "Bakırköy'deki plaza ve iş merkezlerinden Ankara'ya kurumsal ofis taşımalarında IT ekipmanı anti-statik ambalaj ve kablo planı fotoğrafiyle güvence altına alınmaktadır. Gece veya hafta sonu taşıma tercih edilmekte; pazartesi sabahı çalışma ortamı hazır olmaktadır.\n\nArşiv ve gizli belgeler kilitli kolilere konulmakta; imzalı teslim tutanağı düzenlenmektedir. Kurumsal fatura ve sigorta belgesi her ofis taşıması için standarttır.",
        [("bakirkoy", ServisTipi.Fuar)]          = "Bakırköy'deki firmalar için Ankara fuar alanlarına gönderilen stand sistemleri ve tanıtım materyalleri darbe emici ambalajlarla hazırlanmaktadır. Fuar takvimi ve kurulum programına uygun kalkış planı yapılmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu talep üzerine önceden alınmaktadır. Hasar durumunda sigorta kapsamında tutanak tutularak işlemler başlatılmaktadır.",
        [("bakirkoy", ServisTipi.Kamyon)]        = "Ataköy sitelerindeki büyük 3+1 ve 4+1 dairelerden Ankara'ya 12 ton kapalı kasalı kamyon ile tek seferlik taşıma, birden fazla kamyonet seferine göre hem daha ekonomik hem de daha güvenlidir. Geniş site erişim yolları büyük aracın manevrasına olanak tanımaktadır.\n\nTüm eşyalar hareket öncesinde sigorta kapsamına alınmakta ve ayrıntılı envanter listesiyle belgelenmektedir. Ankara'ya varışta ekip eşyaları odaya taşımakta ve büyük mobilyaları monte etmektedir.",
        [("bakirkoy", ServisTipi.Parsiyel)]      = "Bakırköy'den Ankara'ya birkaç parça mobilya, kutu veya tekli beyaz eşya göndermek isteyen müşteriler için parsiyel araç hizmeti ekonomik ve zamanında teslimat sunar. Konsolide sefer içinde gönderilen eşyalar düzgün biçimde ambalajlanarak güvenle iletilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; toplama günü müşteriye önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği mevcuttur.",
        [("bakirkoy", ServisTipi.Ambar)]         = "Bakırköy'deki konutunu boşaltıp Ankara'da anahtar bekleyen ya da taşınma tarihi esnek olan müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; ek nakliye ücretleri o tarih itibarıyla bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── BEYLİKDÜZÜ ──
        [("beylikduzu", ServisTipi.Kamyonet)]      = "Büyükşehir ve Adnan Kahveci mahallelerindeki geniş sitelerden yapılan taşımalarda 3,5 ton kamyonetimiz site girişi ve yükleme yeri prosedürlerine uygun biçimde konumlanmaktadır. Asansörlü yapılarda yükleme oldukça verimli yürütülmekte; saatlik yükleme süresi keşifte önceden belirlenmektedir.\n\nBeylikdüzü'nün planlı kentsel yapısı ve geniş anayolları büyük araç operasyonları için de ideal altyapı sunmaktadır. TEM'e Esenyurt aksından 15 dakikada bağlantı sağlanmakta; sabah 06:30 kalkışla Ankara güzergâhına trafiksiz girilmektedir.",
        [("beylikduzu", ServisTipi.Sehirlerarasi)] = "Beylikdüzü'nün modern site yapısı ve TEM bağlantısının kısalığı sayesinde şehirlerarası araçlar kolayca güzergâha katılmaktadır. Sabah erken yüklemeyle metrobüs koridorundaki trafik yoğunluğu başlamadan araç bölgeyi terk etmektedir.\n\nHer şehirlerarası taşımada envanter listesi ve nakliye sigortası standarttır. Beylikdüzü'nden Ankara'nın tüm ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("beylikduzu", ServisTipi.EvdenEve)]      = "Beylikdüzü'nün geniş bina girişli ve yük asansörlü modern sitelerinde ev nakliyesi verimli planlanmaktadır; site yönetimiyle yükleme saati ve asansör ön rezervasyonu önceden koordine edilmektedir. Büyük mobilyalar söküm-montaj ekibiyle koruyucu ambalajla güvence altına alınmaktadır.\n\nAdnan Kahveci mahallelerindeki büyük 3+1 ve 4+1 dairelerden çıkan eşyalar Ankara'daki yeni adrese teslimatta odaya taşınmakta ve monte edilmektedir. Kapıdan kapıya hizmet anlayışıyla müşteri yeni evine aynı gün yerleşebilmektedir.",
        [("beylikduzu", ServisTipi.Ofis)]          = "Beylikdüzü'ndeki AVM çevresi iş bölgelerinde ve sitelerin zemin kat ofislerinden Ankara'ya kurumsal taşımalarda IT ekipmanı özel ambalajla güvence altına alınmaktadır. Hafta sonu taşıma tercih edilmekte; pazartesi sabahı ofis çalışmaya hazır teslim edilmektedir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her kurumsal taşımada standart olarak sunulmaktadır. Kablo planı fotoğraflama ve Ankara kurulum desteği hizmete dahildir.",
        [("beylikduzu", ServisTipi.Fuar)]          = "Beylikdüzü'ndeki firmalar için Ankara fuar alanlarına gönderilen stand profilleri, display materyalleri ve promosyon gereçleri darbe emici özel ambalajlarla hazırlanmaktadır. TEM'e yakın konumuyla araç zamanında yola çıkarak fuar öncesi teslimat kolaylıkla tamamlanmaktadır.\n\nFuar açılışından 2 gün önce Ankara alanında teslim garanti edilmektedir. Fuar sonrası geri taşıma rezervasyonu ilk operasyonla eş zamanlı alınabilmektedir.",
        [("beylikduzu", ServisTipi.Kamyon)]        = "Beylikdüzü'nün büyük sitelerindeki 3+1 ve 4+1 dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, geniş site yolları sayesinde kolayca organize edilmektedir. Tüm eşyalar envanter listesiyle fotoğraflanmakta ve sigorta kapsamına alınmaktadır.\n\nYükleme sabah 06:30'da başlatılarak araç TEM'e bağlanmaktadır. Ankara'ya varışta ekip büyük mobilyaları odaya taşımakta ve monte etmektedir.",
        [("beylikduzu", ServisTipi.Parsiyel)]      = "Beylikdüzü'nden Ankara'ya birkaç parça mobilya, kutu veya tekli eşya göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Gönderiler haftanın belirli günleri düzenli konsolide sefere dahil edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü müşteriye önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("beylikduzu", ServisTipi.Ambar)]         = "Beylikdüzü'ndeki konutunu boşaltıp Ankara'ya geçiş tarihi bekleniyor ise eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmektedir. Depo kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── ESENYURT ──
        [("esenyurt", ServisTipi.Kamyonet)]      = "Esenyurt'un yoğun konut bloklarında sabah 07:00 sonrasında araç trafiği önemli ölçüde artmakta; 3,5 ton kamyonetimizle yükleme 06:30'da başlatılarak ilçe trafiği öncesinde çıkış yapılmaktadır. Talatpaşa ve Saadetdere'deki asansörlü yapılarda yük koordinasyonu verimli planlanmaktadır.\n\nTEM'e Avcılar veya Başakşehir aksından bağlantı sağlanmakta; güzergâha girdikten sonra Ankara yolu açık akmaktadır. Pınar mahallelerindeki eski konut stoğunda kat başına taşıma süresi keşifte hesaplanmaktadır.",
        [("esenyurt", ServisTipi.Sehirlerarasi)] = "Esenyurt'tan şehirlerarası araçlar sabah 06:30–07:00 arası yüklemeyle ilçe trafiği yoğunlaşmadan TEM'e bağlanmakta; aynı gün Ankara teslimatı tamamlanmaktadır. Yüksek nüfus yoğunluğu nedeniyle erken kalkış standart öneri olmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Esenyurt'tan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("esenyurt", ServisTipi.EvdenEve)]      = "Talatpaşa ve Pınar mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması planlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmaktadır.\n\nEsenyurt'taki büyük 3+1 ve 4+1 dairelerde çok parçalı mobilya takımları parçalara ayrılarak Ankara'ya taşınmakta; teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("esenyurt", ServisTipi.Ofis)]          = "Esenyurt'taki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı özel ambalajla güvence altına alınmakta; gece veya hafta sonu çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı ofis çalışmaya hazır teslim edilmektedir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("esenyurt", ServisTipi.Fuar)]          = "Esenyurt'taki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve promosyon materyalleri darbe emici ambalajlarla hazırlanmaktadır. TEM'e yakın konumuyla araç zamanında yola çıkarak fuar öncesi 2 gün teslimat kolaylıkla tamamlanmaktadır.\n\nFuar sonrası geri taşıma rezervasyonu ilk operasyonla eş zamanlı alınabilmektedir.",
        [("esenyurt", ServisTipi.Kamyon)]        = "Esenyurt'taki büyük 3+1 ve 4+1 dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma verimli biçimde yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:00–06:30 arası başlatılarak araç TEM'e bağlanmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("esenyurt", ServisTipi.Parsiyel)]      = "Esenyurt'tan Ankara'ya birkaç parça eşya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Konsolide yükle birlikte gönderilen eşyalar ekonomik fiyatla zamanında teslim edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.",
        [("esenyurt", ServisTipi.Ambar)]         = "Esenyurt'taki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── BAŞAKŞEHİR ──
        [("basaksehir", ServisTipi.Kamyonet)]      = "Bahçeşehir ve Kayaşehir'deki planlı sitelerde site yönetimiyle yükleme noktası ve asansör ön rezervasyonu koordine edilmekte; 3,5 ton kamyonetimiz geniş bina girişlerine uygun biçimde konumlanmaktadır. Altınşehir'deki büyük konut bloklarında yük asansörleri yüklemeyi önemli ölçüde hızlandırmaktadır.\n\nBaşakşehir'in TEM'e doğrudan bağlantısı İstanbul'un şehirlerarası güzergâha en kısa çıkışlarından birini sunmaktadır; sabah 06:30 kalkışla Ankara yoluna trafiksiz girilmektedir.",
        [("basaksehir", ServisTipi.Sehirlerarasi)] = "Başakşehir TEM'e doğrudan bağlantısıyla İstanbul Avrupa yakasından Ankara güzergâhına en hızlı çıkılan ilçelerden biridir. Şehirlerarası araçlar sabah yüklemesini tamamlar tamamlamaz TEM'e girmekte; İstanbul trafiğinden kaynaklanan zaman kaybı sıfırlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Başakşehir'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("basaksehir", ServisTipi.EvdenEve)]      = "Altınşehir ve Başakşehir Merkez'deki modern konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmaktadır.\n\nBüyük 3+1 ve 4+1 dairelerdeki mobilya takımları parçalara ayrılarak Ankara'ya taşınmakta; teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("basaksehir", ServisTipi.Ofis)]          = "Başakşehir'deki teknoloji, sağlık ve kurumsal firmaların Ankara'ya ofis taşımalarında IT altyapısı güvenli biçimde demonte edilmekte; sunucu ve ağ ekipmanı özel kasalarda iletilmektedir. Hafta sonu taşımayla pazartesi sabahı ofis çalışmaya hazır teslim edilmektedir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("basaksehir", ServisTipi.Fuar)]          = "Başakşehir'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve ekipmanlar darbe emici ambalajlarla hazırlanmaktadır. TEM'e sıfır mesafedeki konumuyla araç zamanında yola çıkarak fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu ilk operasyonla eş zamanlı alınabilmektedir.",
        [("basaksehir", ServisTipi.Kamyon)]        = "Başakşehir'deki büyük sitelerin 3+1 ve 4+1 dairelerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, TEM'e doğrudan bağlantı güzergâhını etkin biçimde kullanmaktadır. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e girilmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("basaksehir", ServisTipi.Parsiyel)]      = "Başakşehir'den Ankara'ya birkaç parça eşya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Konsolide yükle birlikte gönderilen eşyalar ekonomik fiyatla zamanında teslim edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.",
        [("basaksehir", ServisTipi.Ambar)]         = "Başakşehir'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarih itibarıyla bildirilmektedir.",

        // ── ARNAVUTKÖY ──
        [("arnavutkoy", ServisTipi.Kamyonet)]      = "Bolluca ve Haraçcı mahallelerindeki yeni konut sitelerinde site yönetimiyle yükleme noktası ve asansör ön rezervasyonu koordine edilmekte; 3,5 ton kamyonetimiz belirlenen noktaya zamanında konumlanmaktadır. Taşoluk'taki toplu konut projelerinde geniş bina girişleri yükleme hızını artırmaktadır.\n\nArnavutköy'ün İstanbul Havalimanı'na komşu konumu ve TEM'e çevreyolu bağlantısı sayesinde şehirlerarası araçlar 15–20 dakikada güzergâha katılmaktadır. Sabah 06:30 kalkışla Ankara yoluna trafiksiz girilmektedir.",
        [("arnavutkoy", ServisTipi.Sehirlerarasi)] = "Arnavutköy TEM çevreyolu bağlantısıyla İstanbul Avrupa yakasından Ankara güzergâhına hızla çıkılan ilçelerden biridir. Sabah yüklemesiyle araç TEM'e kısa sürede bağlanmakta; aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Arnavutköy'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sunulmaktadır.",
        [("arnavutkoy", ServisTipi.EvdenEve)]      = "Arnavutköy Merkez ve Taşoluk'taki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmaktadır.\n\nBüyük mobilya takımları parçalara ayrılarak Ankara'ya taşınmakta; teslimatta monte ve odaya yerleştirme hizmeti dahildir.",
        [("arnavutkoy", ServisTipi.Ofis)]          = "Arnavutköy'deki işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı özel ambalajla güvence altına alınmakta; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Kurumsal fatura ve sigorta belgesi standart olarak sunulmaktadır.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir.",
        [("arnavutkoy", ServisTipi.Fuar)]          = "Arnavutköy'deki firmalar için Ankara fuar alanlarına taşınan stand ekipmanları ve promosyon materyalleri darbe emici ambalajlarla hazırlanmaktadır. TEM'e yakın konum fuar öncesi teslimat zamanlamasına esneklik sağlamaktadır.\n\nFuar açılışından 2 gün önce teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma rezervasyonu önceden alınabilmektedir.",
        [("arnavutkoy", ServisTipi.Kamyon)]        = "Arnavutköy'deki büyük konut sitelerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, TEM'e yakın güzergâh avantajıyla verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah erken başlatılmakta; Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("arnavutkoy", ServisTipi.Parsiyel)]      = "Arnavutköy'den Ankara'ya birkaç parça eşya veya kargo göndermek için parsiyel araç hizmeti ekonomik ve zamanında teslimat sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.",
        [("arnavutkoy", ServisTipi.Ambar)]         = "Arnavutköy'deki konutunu boşaltıp Ankara'da anahtar bekleyen ya da taşınma tarihi esnek olan müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Haftalık ya da aylık esnek depolama süreleri sunulmaktadır.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmektedir.",

        // ── HADIMKÖY ──
        [("hadimkoy", ServisTipi.Kamyonet)]      = "Hadımköy Merkez mahallelerindeki konut bölgelerine 3,5 ton kamyonetimiz sorunsuz erişmekte; OSB çevresindeki geniş araç yollarına alışkın ekip yükleme koordinasyonunu hızla tamamlamaktadır. Yeni konut sitelerinde geniş bina girişleri büyük mobilyaların çıkarılmasını kolaylaştırmakta; dar mahalle sokaklarında kamyonet boyutu avantaj sağlamaktadır.\n\nHadımköy'ün TEM girişine olan 5 dakikalık mesafesi, yükleme tamamlanır tamamlanmaz aracın İstanbul trafiğine hiç karışmadan Ankara güzergâhına çıkmasını sağlamaktadır. Sabah 06:30 kalkışla Ankara'ya öğleden önce rahatça varılmakta; gecikme riski en düşük güzergâhlardan biri bu hattır.",
        [("hadimkoy", ServisTipi.Sehirlerarasi)] = "Hadımköy TEM girişine fiilen sıfır mesafedeki konumuyla İstanbul Avrupa yakasından Ankara güzergâhına en hızlı çıkılan ilçedir. Şehirlerarası araç yükleme tamamlanır tamamlanmaz TEM'e girişini yaparak İstanbul trafiğini tamamen atlamakta; bu güzergâh özellikle mesai saatlerinde rakipsiz avantaj sunmaktadır.\n\nTüm eşyalar yükleme öncesinde envanter listesiyle fotoğraflanmakta ve nakliye sigortasına dahil edilmektedir. Hadımköy'den Ankara'nın Çankaya, Çayyolu, Eryaman ve Keçiören gibi tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("hadimkoy", ServisTipi.EvdenEve)]      = "Hadımköy Merkez ve çevre konut sitelerindeki dairelerde asansör ön rezervasyonu yönetimle yapılmakta; büyük mobilyaların söküm-montaj süresi keşifte belirlenerek günlük plan hazırlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunarak Ankara yoluna hazırlanmaktadır.\n\nOSB çevresindeki endüstriyel alana yakın sitelerde geniş araç erişim yolları büyük kamyon kullanımına da elverişlidir. Ankara'daki yeni konuta varışta ekibimiz mobilyaları monte etmekte ve eşyaları odaya yerleştirmekte; müşteri aynı gün yerleşik hayatına geçmektedir.",
        [("hadimkoy", ServisTipi.Ofis)]          = "Hadımköy OSB'deki üretim ve lojistik firmalarının Ankara'ya kurumsal taşımalarında büyük araç altyapısına alışkın ekip ve geniş yol ağı avantaj sağlamaktadır. IT ekipmanı anti-statik ambalajla, sunucu ve ağ cihazları özel koruyucu kasalarla iletilmektedir.\n\nHafta sonu veya gece çalışmayla iş sürekliliği korunmakta; pazartesi sabahı personel çalışmaya hazır ofiste başlamaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her ofis taşıması için standart olarak sunulmaktadır.",
        [("hadimkoy", ServisTipi.Fuar)]          = "Hadımköy'deki sanayi ve üretim firmalarının Ankara CNR veya Tüyap fuar alanlarına taşınan ekipmanları vibrasyon emici ambalajlarla güvence altına alınmaktadır. Ağır sanayi gereçleri için kamyon, daha küçük stand materyalleri için kamyonet seçilmekte; araç tipi yük miktarına göre belirlenmektedir.\n\nTEM'e sıfır mesafedeki konumun sağladığı esneklikle kalkış vaktinde geç bile kalınsa fuar öncesi 2 gün teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma rezervasyonu ilk operasyonla eş zamanlı alındığında öncelikli araç tahsisi sağlanmaktadır.",
        [("hadimkoy", ServisTipi.Kamyon)]        = "Hadımköy OSB çevresindeki sanayi tesisleri veya büyük konut sitelerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile taşıma, TEM girişine 5 dakikalık mesafenin sağladığı avantajla son derece verimli yürütülmektedir. Büyük araç trafiğine alışkın geniş yollar yükleme operasyonunu kolaylaştırmaktadır.\n\nTüm eşyalar hareket öncesinde sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir. Ankara'ya varışta ekip büyük mobilyaları odaya taşımakta ve monte etmektedir; sabah 06:30 kalkışla öğleden önce teslimat tamamlanmaktadır.",
        [("hadimkoy", ServisTipi.Parsiyel)]      = "Hadımköy'den Ankara'ya birkaç parça mobilya, kargo kutusu veya az miktarda eşya göndermek için parsiyel araç hizmeti, tam araç maliyetinin çok altında ekonomik çözüm sunmaktadır. TEM'e yakınlık sayesinde konsolide sefere dahil edilen gönderiler en kısa güzergâhtan zamanında teslim edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü rezervasyon sırasında müşteriye bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("hadimkoy", ServisTipi.Ambar)]         = "Hadımköy'deki konutunu veya iş yerini boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera sistemi, nem kontrolü ve yangın önlemiyle donatılmış olup hassas eşyalar için bireysel kilitli alan tahsis edilebilmektedir.",

        // ── İKİTELLİ ──
        [("ikitelli", ServisTipi.Kamyonet)]      = "Kazım Karabekir ve Ziya Gökalp mahallelerindeki konut bloklarında 3,5 ton kamyonetimiz asansör koordinasyonuyla verimli yükleme tamamlamaktadır; OSB girişindeki büyük araç trafiğine alışkın ekip yükleme planlamasını hızla organize etmektedir. Kanarya ve Mehmet Akif mahallelerindeki yeni yapılarda ise geniş bina girişleri büyük mobilyaların sorunsuz çıkarılmasını sağlamaktadır.\n\nİkitelli'den TEM'e Başakşehir veya Küçükçekmece aksından bağlantı kurulmakta; sabah OSB giriş-çıkış trafiği yoğunlaşmadan önce yükleme tamamlanarak Ankara güzergâhına girilmektedir. Sabah 06:30 kalkışla öğleden önce Ankara teslimatı rahatlıkla sağlanmaktadır.",
        [("ikitelli", ServisTipi.Sehirlerarasi)] = "İkitelli, İstanbul'un en büyük OSB'sine ev sahipliği yapmasıyla birlikte kurumsal ve bireysel şehirlerarası taşımalarda deneyimli bir lojistik bölgesidir. Başakşehir aksıyla TEM'e bağlantı çok kısa sürede sağlanmakta; sabah 06:30 yüklemesiyle aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. İkitelli'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("ikitelli", ServisTipi.EvdenEve)]      = "Kazım Karabekir ve Mehmet Akif mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nOSB çevresindeki büyük konut sitelerinde geniş araç erişim yolları kamyon kullanımına da imkân tanımaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirerek müşterinin aynı gün yerleşmesini sağlamaktadır.",
        [("ikitelli", ServisTipi.Ofis)]          = "İkitelli OSB'deki üretim, tekstil ve teknoloji firmalarının Ankara'ya kurumsal taşımalarında IT altyapısı güvenli biçimde demonte edilmektedir; sunucu ve ağ ekipmanı özel koruyucu kasalarda, kablolama fotoğraflanarak iletilmektedir. Depo ekipmanı ve büyük sanayi makineleri için ek araç planlaması gerektiğinde yapılmaktadır.\n\nHafta sonu veya gece taşımayla iş sürekliliği korunmakta; kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("ikitelli", ServisTipi.Fuar)]          = "İkitelli'deki sanayi ve tekstil firmalarının Ankara fuar alanlarına taşınan ürün ve stand materyalleri vibrasyon emici ambalajlarla güvence altına alınmaktadır. Ağır numune veya sanayi gereçleri için kamyon, küçük stand malzemeleri için kamyonet seçilmektedir.\n\nFuar açılışından 2 gün önce teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma için aynı ambalaj standardı uygulanmakta; hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("ikitelli", ServisTipi.Kamyon)]        = "İkitelli OSB çevresindeki sanayi tesisleri veya büyük konut sitelerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, OSB'nin büyük araç altyapısından ve TEM'e yakın güzergâhtan etkin biçimde yararlanmaktadır. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e Başakşehir aksından bağlanılmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("ikitelli", ServisTipi.Parsiyel)]      = "İkitelli'den Ankara'ya az eşya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli konsolide sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü rezervasyon sırasında bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("ikitelli", ServisTipi.Ambar)]         = "İkitelli'deki konutunu veya iş yerini boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── AVCILAR ──
        [("avcilar", ServisTipi.Kamyonet)]      = "Cihangir ve Tahtakale mahallelerindeki konutlara 3,5 ton kamyonetimiz sorunsuz erişmekte; Firuzköy'ün eski konut dokusundaki dar sokaklarda kamyonet boyutu avantaj sağlamaktadır. Ambarlı liman bölgesine alışkın ekip, büyük araçlarla da lojistik operasyon planlamasını etkin biçimde yönetmektedir.\n\nE-5'e hızla ulaşılabilen ilçede TEM bağlantısı Küçükçekmece veya Esenyurt aksından sağlanmaktadır; sabah 06:30 yüklemesiyle Ankara güzergâhına trafiksiz girilmektedir. Üniversite kampüsü çevresindeki yoğun araç trafiği nedeniyle yükleme saati önceden planlanmaktadır.",
        [("avcilar", ServisTipi.Sehirlerarasi)] = "Avcılar, E-5 üzerinde konumlanmasıyla şehirlerarası araçların Ankara güzergâhına hızla çıkabildiği Avrupa yakası ilçelerinden biridir. E-5'ten TEM'e Küçükçekmece veya Esenyurt aksından geçilerek Ankara yoluna girilmekte; sabah 06:30 yüklemesiyle aynı gün teslimat tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Avcılar'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("avcilar", ServisTipi.EvdenEve)]      = "Üniversite ve Ambarlı mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nÖğrenci konutlarından küçük daireler için parsiyel araç veya kamyonet seçeneği sunulmakta; büyük 3+1 ve 4+1 daireler için kamyon planlaması yapılmaktadır. Ankara'da teslimatta ekip mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("avcilar", ServisTipi.Ofis)]          = "Avcılar'daki ticari işletmeler ve küçük ofislerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("avcilar", ServisTipi.Fuar)]          = "Avcılar'daki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. E-5 güzergâhı sayesinde TEM bağlantısı hızla sağlanmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("avcilar", ServisTipi.Kamyon)]        = "Avcılar'daki büyük sitelerin 3+1 ve 4+1 dairelerinden Ankara'ya 12 ton kapalı kasalı kamyon ile tek seferlik taşıma, E-5 üzerindeki konumun Ankara güzergâhına sağladığı avantajla verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e Esenyurt aksından bağlanılmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("avcilar", ServisTipi.Parsiyel)]      = "Avcılar'dan Ankara'ya öğrenci, bekar veya az eşyalı taşımalar için parsiyel araç hizmeti ekonomik ve zamanında teslimat sunar. Üniversite mahallelerindeki küçük daireler için bu seçenek sıklıkla tercih edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("avcilar", ServisTipi.Ambar)]         = "Avcılar'daki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── BÜYÜKÇEKMECe ──
        [("buyukcekemece", ServisTipi.Kamyonet)]      = "Mimarsinan ve Kumburgaz'ın büyük sahil sitelerindeki geniş araç yollarında 3,5 ton kamyonetimiz sorunsuz çalışmakta; Pınarca ve Güzelce'nin kalıcı konut bölgelerinde asansör koordinasyonuyla yükleme verimli biçimde tamamlanmaktadır. Yaz döneminde yazlık konut trafiği yoğunlaştığından yükleme saatinin erken planlanması önerilmektedir.\n\nE-5 ve TEM'e Avcılar veya Esenyurt aksından bağlanılmakta; sabah 06:30 kalkışla Ankara güzergâhına trafiksiz girilmektedir. Site girişlerinde güvenlik prosedürleri önceden yönetimle koordine edilmektedir.",
        [("buyukcekemece", ServisTipi.Sehirlerarasi)] = "Büyükçekmece, Marmara kıyısındaki sakin dokusu ve E-5 bağlantısıyla şehirlerarası araçların Ankara güzergâhına hızla çıkabildiği batı İstanbul ilçesidir. E-5'ten TEM'e Avcılar ya da Esenyurt aksından geçilerek Ankara yoluna girilmekte; sabah 06:30 yüklemesiyle aynı gün teslimat tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Büyükçekmece'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("buyukcekemece", ServisTipi.EvdenEve)]      = "Pınarca ve Güzelce'deki büyük konut sitelerinde asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nKumburgaz sahil kesimindeki yazlık konutlardan yaz sonu veya bahar geçiş dönemlerinde talep artmaktadır; erken rezervasyon önerilmektedir. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("buyukcekemece", ServisTipi.Ofis)]          = "Büyükçekmece'deki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("buyukcekemece", ServisTipi.Fuar)]          = "Büyükçekmece'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. E-5 ve TEM bağlantısının güvenilir güzergâhı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("buyukcekemece", ServisTipi.Kamyon)]        = "Büyükçekmece'nin büyük sahil sitelerindeki 3+1 ve 4+1 konutlardan Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik sigortalı taşıma yapılmaktadır. Geniş site araç yolları kamyon yüklemesini kolaylaştırmakta; tüm eşyalar hareket öncesinde envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak E-5'ten TEM'e aktarımla Ankara yoluna girilmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("buyukcekemece", ServisTipi.Parsiyel)]      = "Büyükçekmece'den Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü rezervasyon sırasında müşteriye bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("buyukcekemece", ServisTipi.Ambar)]         = "Büyükçekmece'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Yazlık boşaltmalarında da köprü dönem depolaması sıklıkla tercih edilmektedir.\n\nDepolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir. Çıkışta eşyalar Ankara adresine ekibimizle teslim edilmektedir.",

        // ── SİLİVRİ ──
        [("silivri", ServisTipi.Kamyonet)]      = "Selimpaşa ve Gümüşyaka'daki büyük konut sitelerinin geniş araç yollarında 3,5 ton kamyonetimiz sorunsuz çalışmakta; bağ bölgelerinin dar köy yollarında ise kamyonet boyutu büyük araç yerine standart tercih olmaktadır. Site girişlerinde güvenlik prosedürleri önceden koordine edilmektedir.\n\nE-5 ve TEM'e Büyükçekmece güzergâhından bağlantı sağlanmakta; sabah 06:30 kalkışla yolun henüz sakin olduğu saatte Ankara güzergâhına girilmektedir. Silivri'nin İstanbul'un batı ucunda yer alması güzergâhı uzatmamakta; Ankara'ya aynı gün teslimat rahatlıkla tamamlanmaktadır.",
        [("silivri", ServisTipi.Sehirlerarasi)] = "Silivri İstanbul'un en batısındaki ilçesi olmakla birlikte E-5 ve TEM bağlantısı sayesinde Ankara'ya aynı gün teslimat standardını korumaktadır. Büyükçekmece güzergâhından TEM'e kısa sürede ulaşılmakta; sabah 06:00–06:30 yüklemesiyle araç İstanbul trafiğini geride bırakmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Silivri'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("silivri", ServisTipi.EvdenEve)]      = "Silivri Merkez ve Ortaköy'deki konut sitelerinde asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nYazlık konutlardan kalıcı konuta geçiş dönemlerinde (ekim ve nisan) yoğun talep yaşanmakta; erken rezervasyon önerilmektedir. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("silivri", ServisTipi.Ofis)]          = "Silivri'deki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Uzun güzergâh nedeniyle yükleme öncesinde güzergâh planlaması ayrıca yapılmaktadır.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır. Arşiv belgeleri kilitli kolilere konulmaktadır.",
        [("silivri", ServisTipi.Fuar)]          = "Silivri'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve ekipmanlar darbe emici ambalajlarla hazırlanmaktadır. Uzun güzergâh nedeniyle kalkış sabah 06:00'a alınmakta; fuar öncesi 2 gün teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("silivri", ServisTipi.Kamyon)]        = "Silivri'deki büyük konut siteleri veya bağ evlerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik sigortalı taşıma yapılmaktadır. Geniş site araç yolları kamyon yüklemesini kolaylaştırmakta; tüm eşyalar hareket öncesinde envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:00'da başlatılarak E-5 ve TEM güzergâhından Ankara yoluna girilmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("silivri", ServisTipi.Parsiyel)]      = "Silivri'den Ankara'ya birkaç parça mobilya, kargo kutusu veya az miktarda eşya göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü rezervasyon sırasında müşteriye bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("silivri", ServisTipi.Ambar)]         = "Silivri'deki konutunu veya yazlığını boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Yazlık–şehir geçiş dönemlerinde köprü depolama çok sık tercih edilen bir seçenektir.\n\nDepolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir. Çıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── ÇATALCA ──
        [("catalca", ServisTipi.Kamyonet)]      = "Çatalca Merkez ve Kapaklı mahallelerine 3,5 ton kamyonetimiz sorunsuz erişmekte; köy bölgelerindeki dar toprak yollarda ise kamyonet boyutu büyük araçlara kıyasla belirgin avantaj sağlamaktadır. Adres bazlı yol değerlendirmesi rezervasyon aşamasında yapılarak olası aksaklıklar önceden giderilmektedir.\n\nE-5 ve TEM'e Silivri ya da Büyükçekmece üzerinden bağlantı kurulmakta; sabah 06:00 kalkışla İstanbul trafiğini aşmadan Ankara güzergâhına girilmektedir. Uzak mahallelerde yükleme saatinin özellikle erken tutulması önerilmektedir.",
        [("catalca", ServisTipi.Sehirlerarasi)] = "Çatalca İstanbul'un yüzölçümü en geniş ilçesi olup kırsal güzergâhı nedeniyle şehirlerarası araçlarda kalkış sabah 06:00'a ayarlanmaktadır. Silivri veya Büyükçekmece üzerinden E-5 ve TEM'e bağlantı sağlanmakta; aynı gün Ankara teslimatı standart olarak tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Çatalca'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sağlanmaktadır.",
        [("catalca", ServisTipi.EvdenEve)]      = "Çatalca Merkez'deki konutlarda asansör koordinasyonu ve söküm-montaj ekibi dahil kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nKöy ve kırsal kesimlerdeki müstakil evlerde büyük bahçe mobilyaları ve ağır eşyalar için araç planlaması adres bazlı yapılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("catalca", ServisTipi.Ofis)]          = "Çatalca'daki küçük ticari işletmelerin Ankara'ya taşınmalarında IT ekipmanı güvenli ambalajla paketlenmekte; uzun güzergâh gözetilerek sabah erken kalkış planlanmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi standart olarak sunulmaktadır.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Gece çalışma seçeneği gerektiğinde planlanabilmektedir.",
        [("catalca", ServisTipi.Fuar)]          = "Çatalca'daki firmalar için Ankara fuar taşımalarında uzun güzergâh nedeniyle kalkış fuar açılışından en az 2 gün öncesine alınmakta; stand ve ekipmanlar darbe emici ambalajlarla güvence altına alınmaktadır. Zamanında teslimat için rezervasyon erken yapılmaktadır.\n\nFuar sonrası geri taşıma için aynı ambalaj standardı uygulanmakta; hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("catalca", ServisTipi.Kamyon)]        = "Çatalca'daki büyük konutlar veya çiftlik tesislerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik sigortalı taşıma yapılmaktadır. Ana karayoluna erişim mümkün olan adreslerde kamyon doğrudan yükleme yapabilmekte; uzak köy noktalarında önce kamyonete aktarım gerekebilmektedir.\n\nYükleme sabah 06:00'da başlatılarak Silivri–TEM güzergâhından Ankara yoluna girilmektedir. Tüm eşyalar hareket öncesinde sigorta kapsamına alınmaktadır.",
        [("catalca", ServisTipi.Parsiyel)]      = "Çatalca'dan Ankara'ya birkaç parça eşya veya kargo göndermek için parsiyel araç hizmeti ekonomik çözüm sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü rezervasyon sırasında müşteriye bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("catalca", ServisTipi.Ambar)]         = "Çatalca'daki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── KÜÇÜKÇEKMECe ──
        [("kucukcekemece", ServisTipi.Kamyonet)]      = "Atakent sitelerinin geniş bina girişleri ve yük asansörleri 3,5 ton kamyonetimizin verimli yükleme yapmasını sağlamaktadır; Halkalı ve İnönü mahallelerindeki eski konut stokunda ise kamyonet boyutu dar yol ve giriş aralıklarına uyum sağlamaktadır. Site girişleri güvenlik prosedürleri önceden yönetimle koordine edilmektedir.\n\nE-5 üzerindeki konumuyla ilçe Ankara güzergâhına doğrudan bağlantı sunmakta; sabah 06:30 yüklemesiyle trafik yoğunlaşmadan önce Ankara yoluna girilmektedir. Halkalı'nın tren bağlantısı da bölgenin ulaşım kapasitesini artırmaktadır.",
        [("kucukcekemece", ServisTipi.Sehirlerarasi)] = "Küçükçekmece, E-5 üzerindeki konumuyla Ankara güzergâhına doğrudan bağlantı sunan Avrupa yakası ilçelerinden biridir. Sabah 06:30 yüklemesiyle araç E-5'ten TEM'e Esenyurt veya Bakırköy aksından geçerek Ankara yoluna girmekte; aynı gün teslimat tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Küçükçekmece'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("kucukcekemece", ServisTipi.EvdenEve)]      = "Atakent ve Cennet mahallelerindeki büyük konut sitelerinde asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nHalkalı ve İnönü'nün eski yapılarında asansör yoksa kat başına ekip planlaması yapılmakta; büyük mobilyalar merdivenden güvenle çıkarılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("kucukcekemece", ServisTipi.Ofis)]          = "Küçükçekmece'deki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("kucukcekemece", ServisTipi.Fuar)]          = "Küçükçekmece'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. E-5 güzergâhı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("kucukcekemece", ServisTipi.Kamyon)]        = "Atakent'teki büyük sitelerin 3+1 ve 4+1 dairelerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, E-5 güzergâhının avantajını tam kullanmaktadır. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak E-5'ten TEM'e aktarımla Ankara yoluna girilmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("kucukcekemece", ServisTipi.Parsiyel)]      = "Küçükçekmece'den Ankara'ya birkaç parça mobilya veya kargo göndermek için parsiyel araç hizmeti ekonomik ve zamanında teslimat sunar. Konsolide sefere dahil edilen gönderiler 1–2 iş günü içinde Ankara adresine ulaşmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü rezervasyon sırasında müşteriye bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("kucukcekemece", ServisTipi.Ambar)]         = "Küçükçekmece'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── GÜNGÖREN ──
        [("gungoren", ServisTipi.Kamyonet)]      = "Güngören Merkez ve Tozkoparan'ın dar iç sokaklarında büyük kamyonların erişimi güçleşebilmekte; 3,5 ton kamyonetimiz bina önüne en yakın noktaya konumlanarak hızlı yükleme tamamlamaktadır. Merter'deki tekstil atölyeleri ve işyeri çevresindeki geniş arterlerde ise kamyon erişimi de sorunsuz sağlanmaktadır.\n\nBakırköy veya Bağcılar aksından TEM'e bağlantı kurulmakta; sabah 07:00 öncesi kalkışla araç Ankara güzergâhına girmektedir. İlçe genelinde araç park kısıtlarına karşı bina önü geçici duraklama koordinasyonu yükleme planının ayrılmaz parçasıdır.",
        [("gungoren", ServisTipi.Sehirlerarasi)] = "Güngören, Bakırköy ve Bağcılar akslarıyla hem E-5 hem TEM'e hızla bağlanabilen merkezi Avrupa yakası ilçelerinden biridir. Sabah 06:30–07:00 yüklemesiyle araç trafik yoğunlaşmadan önce İstanbul'u terk etmekte; aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Güngören'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("gungoren", ServisTipi.EvdenEve)]      = "Güngören Merkez ve Tozkoparan'daki çok katlı konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nDar sokaklardaki eski apartmanlarda asansör yoksa kat başına ekip planlaması yapılmakta; büyük mobilyalar merdivenden güvenle çıkarılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("gungoren", ServisTipi.Ofis)]          = "Güngören'deki tekstil, ticaret ve küçük üretim işletmelerinin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("gungoren", ServisTipi.Fuar)]          = "Güngören'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım materyalleri darbe emici ambalajlarla hazırlanmaktadır. Bakırköy veya Bağcılar aksının TEM bağlantısı güvenilir kalkış zamanlaması sağlamaktadır.\n\nFuar açılışından 2 gün önce teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır.",
        [("gungoren", ServisTipi.Kamyon)]        = "Güngören'deki 3+1 ve 4+1 büyük dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, Bakırköy aksından TEM'e bağlantıyla verimli yürütülmektedir. Yükleme noktası geniş artere yakın belirlenerek kamyon erişimi sağlanmaktadır.\n\nTüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("gungoren", ServisTipi.Parsiyel)]      = "Güngören'den Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli konsolide sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("gungoren", ServisTipi.Ambar)]         = "Güngören'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── BAHÇELİEVLER ──
        [("bahcelievler", ServisTipi.Kamyonet)]      = "Kocasinan ve Şirinevler'in yüksek katlı konut bloklarında 3,5 ton kamyonetimiz asansör koordinasyonuyla verimli yükleme tamamlamaktadır. Zafer ve Cumhuriyet mahallelerindeki eski konut stokunda dar sokaklar için kamyonet boyutu büyük araçlara kıyasla avantajlıdır.\n\nE-5 üzerindeki konumuyla ilçe Ankara güzergâhına doğrudan bağlantı sunmakta; Şirinevler aksından TEM'e de hızla ulaşılmaktadır. Sabah 06:30 kalkışla trafik yoğunlaşmadan önce Ankara yoluna girilmektedir.",
        [("bahcelievler", ServisTipi.Sehirlerarasi)] = "Bahçelievler E-5 üzerindeki konumuyla Ankara güzergâhına doğrudan erişen Avrupa yakası ilçelerinden biridir. Sabah 06:30 yüklemesiyle araç E-5'ten TEM'e Şirinevler aksından geçerek Ankara yoluna girmekte; aynı gün teslimat standart olarak tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Bahçelievler'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sağlanmaktadır.",
        [("bahcelievler", ServisTipi.EvdenEve)]      = "Zafer ve Cumhuriyet mahallelerindeki çok katlı konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nŞirinevler ve Kocasinan'daki asansörsüz eski yapılarda kat başına ekip planlaması yapılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("bahcelievler", ServisTipi.Ofis)]          = "Bahçelievler'deki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("bahcelievler", ServisTipi.Fuar)]          = "Bahçelievler'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. E-5 ve TEM bağlantısının güvenilir güzergâhı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("bahcelievler", ServisTipi.Kamyon)]        = "Bahçelievler'deki büyük 3+1 ve 4+1 dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, E-5 güzergâhının avantajını tam kullanmaktadır. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak E-5'ten TEM'e aktarımla Ankara yoluna girilmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("bahcelievler", ServisTipi.Parsiyel)]      = "Bahçelievler'den Ankara'ya birkaç parça mobilya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli konsolide sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("bahcelievler", ServisTipi.Ambar)]         = "Bahçelievler'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── BAĞCILAR ──
        [("bagcilar", ServisTipi.Kamyonet)]      = "Bağcılar Merkez ve Kirazlı'daki yüksek katlı konut bloklarında 3,5 ton kamyonetimiz asansör koordinasyonuyla verimli yükleme tamamlamaktadır. Mahmutbey'deki bazı dar iç sokaklarda kamyonet boyutu büyük araçlara kıyasla manevra avantajı sağlamaktadır.\n\nTEM'e Bağcılar çevreyolu veya Esenyurt aksından bağlantı kurulmakta; sabah 07:00 öncesi kalkışla araç Ankara güzergâhına girmektedir. İlçenin yoğun nüfusu nedeniyle sabah erken yükleme başlangıcı araç çıkışını önemli ölçüde kolaylaştırmaktadır.",
        [("bagcilar", ServisTipi.Sehirlerarasi)] = "Bağcılar, TEM'e Bağcılar çevreyolu üzerinden doğrudan bağlantı sunan Avrupa yakası ilçelerinden biridir. Sabah 06:30–07:00 yüklemesiyle araç trafik yoğunlaşmadan önce İstanbul'u terk etmekte; aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Bağcılar'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("bagcilar", ServisTipi.EvdenEve)]      = "Göztepe ve Mahmutbey mahallelerindeki çok katlı konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nEski konut stokunda asansör yoksa kat başına ekip planlaması yapılmakta; büyük mobilyalar merdivenden güvenle çıkarılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("bagcilar", ServisTipi.Ofis)]          = "Bağcılar'daki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("bagcilar", ServisTipi.Fuar)]          = "Bağcılar'daki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. TEM'e çevreyolu bağlantısının güvenilir güzergâhı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("bagcilar", ServisTipi.Kamyon)]        = "Bağcılar'daki büyük 3+1 ve 4+1 dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, Bağcılar çevreyolundan TEM'e bağlantıyla verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e hızla bağlanılmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("bagcilar", ServisTipi.Parsiyel)]      = "Bağcılar'dan Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("bagcilar", ServisTipi.Ambar)]         = "Bağcılar'daki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── ESENLER ──
        [("esenler", ServisTipi.Kamyonet)]      = "Esenler'de İstanbul Büyük Otogar'ın varlığı büyük araç trafiğini normalleştirmiş olmakta; 3,5 ton kamyonetimiz konut mahallelerine sorunsuz erişirken dar iç sokaklarda manevra avantajı sağlamaktadır. Kemer ve Çiftlik mahallelerindeki yeni yapılarda geniş bina girişleri yüklemeyi verimli kılmaktadır.\n\nTEM'e Bağcılar veya Bayrampaşa aksından bağlantı kurulmakta; sabah 07:00 öncesi kalkışla araç Ankara güzergâhına girmektedir. Otogar bölgesindeki yoğun trafikten kaçınmak için yükleme saati erken tutulmaktadır.",
        [("esenler", ServisTipi.Sehirlerarasi)] = "Esenler, Büyük Otogar'ın coğrafi merkezinde yer almasıyla şehirlerarası ulaşıma alışkın bir ilçedir. Bağcılar aksından TEM'e bağlanan araç, sabah 06:30 yüklemesiyle trafik yoğunlaşmadan önce Ankara güzergâhına girmekte; aynı gün teslimat standart olarak tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Esenler'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sağlanmaktadır.",
        [("esenler", ServisTipi.EvdenEve)]      = "Turgut Reis ve Nene Hatun mahallelerindeki çok katlı konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nEski konut stokunda asansör yoksa kat başına ekip planlaması yapılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("esenler", ServisTipi.Ofis)]          = "Esenler'deki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("esenler", ServisTipi.Fuar)]          = "Esenler'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Bağcılar–TEM güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("esenler", ServisTipi.Kamyon)]        = "Esenler'deki büyük dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, Bağcılar aksından TEM'e bağlantıyla verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e hızla bağlanılmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("esenler", ServisTipi.Parsiyel)]      = "Esenler'den Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("esenler", ServisTipi.Ambar)]         = "Esenler'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── BAYRAMPAŞA ──
        [("bayrampasa", ServisTipi.Kamyonet)]      = "Bayrampaşa Merkez ve Muratpaşa mahallelerindeki bazı dar iç sokaklarda 3,5 ton kamyonet büyük araçlara kıyasla belirgin manevra avantajı sağlamaktadır; geniş arterlere yakın adreslerde ise kamyon erişimi de sorunsuz sağlanmaktadır. İsmetpaşa mahallelerindeki konut bloklarında asansör koordinasyonu ile yükleme verimli biçimde planlanmaktadır.\n\nE-5 ve TEM'e Zeytinburnu veya Esenler aksından kısa sürede ulaşılmakta; sabah 06:30 kalkışla araç Ankara güzergâhına girmektedir. İlçenin E-5'e yakınlığı şehirlerarası nakliyatlarda zaman avantajı sunmaktadır.",
        [("bayrampasa", ServisTipi.Sehirlerarasi)] = "Bayrampaşa, E-5 ve TEM akslarına yakın konumuyla şehirlerarası araçların Ankara güzergâhına hızla çıkabildiği ilçelerden biridir. Zeytinburnu veya Esenler aksından TEM'e bağlanan araç, sabah 06:30 yüklemesiyle aynı gün Ankara teslimatını tamamlamaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Bayrampaşa'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("bayrampasa", ServisTipi.EvdenEve)]      = "Kocatepe ve İsmetpaşa mahallelerindeki yüksek katlı konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nEski konut stokunda asansör yoksa kat başına ekip planlaması yapılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("bayrampasa", ServisTipi.Ofis)]          = "Bayrampaşa'daki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("bayrampasa", ServisTipi.Fuar)]          = "Bayrampaşa'daki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. E-5 ve TEM bağlantısının güvenilir güzergâhı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("bayrampasa", ServisTipi.Kamyon)]        = "Bayrampaşa'daki 3+1 ve büyük dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, E-5 güzergâhının avantajını tam kullanmaktadır. Yükleme noktası geniş artere yakın belirlenerek kamyon erişimi sağlanmaktadır.\n\nTüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("bayrampasa", ServisTipi.Parsiyel)]      = "Bayrampaşa'dan Ankara'ya birkaç parça mobilya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("bayrampasa", ServisTipi.Ambar)]         = "Bayrampaşa'daki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── GAZİOSMANPAŞA ──
        [("gaziosmanpasa", ServisTipi.Kamyonet)]      = "Barbaros ve Karadeniz mahallelerinin yoğun sokak dokusunda 3,5 ton kamyonetimiz dar aralıklara kolaylıkla girmekte; bina önü duraklama noktası önceden belirlenerek hızlı yükleme gerçekleştirilmektedir. Yenidoğan'daki kentsel dönüşüm projelerinin yeni yapılarında ise geniş bina girişleri ve yük asansörleri operasyonu verimli kılmaktadır.\n\nTEM'e Sultangazi veya Eyüpsultan aksından ulaşılmakta; sabah 06:30 kalkışla araç Ankara güzergâhına girmektedir. Geniş arterlere yakın adreslerde kamyon erişimi de mümkün olmakta; araç tipi adres bazlı değerlendirilmektedir.",
        [("gaziosmanpasa", ServisTipi.Sehirlerarasi)] = "Gaziosmanpaşa, Sultangazi ve Eyüpsultan akslarıyla TEM'e bağlantı kuran kuzey Avrupa yakası ilçelerinden biridir. Sabah 06:30 yüklemesiyle araç trafik yoğunlaşmadan önce İstanbul'u terk etmekte; aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Gaziosmanpaşa'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("gaziosmanpasa", ServisTipi.EvdenEve)]      = "Barbaros ve Karadeniz mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nYenidoğan'daki kentsel dönüşüm yapılarında yük asansörü planlamasıyla yükleme verimli biçimde tamamlanmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("gaziosmanpasa", ServisTipi.Ofis)]          = "Gaziosmanpaşa'daki ticari işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("gaziosmanpasa", ServisTipi.Fuar)]          = "Gaziosmanpaşa'daki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Sultangazi–TEM güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("gaziosmanpasa", ServisTipi.Kamyon)]        = "Gaziosmanpaşa'daki 3+1 ve büyük dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, geniş arterlere yakın yükleme noktası seçilerek verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e Sultangazi aksından bağlanılmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("gaziosmanpasa", ServisTipi.Parsiyel)]      = "Gaziosmanpaşa'dan Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("gaziosmanpasa", ServisTipi.Ambar)]         = "Gaziosmanpaşa'daki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── SULTANGAZİ ──
        [("sultangazi", ServisTipi.Kamyonet)]      = "Cebeci ve Uğur Mumcu mahallelerindeki planlı konut sitelerinde 3,5 ton kamyonetimiz asansör koordinasyonuyla verimli yükleme tamamlamaktadır. Sultançiftliği ve Habibler mahallelerinin bazı dar sokaklarında kamyonet boyutu büyük araçlara kıyasla manevra avantajı sağlamakta; geniş arterlere yakın adreslerde kamyon erişimi de mümkündür.\n\nTEM'e Arnavutköy veya Eyüpsultan aksından ulaşılmakta; sabah 06:30 kalkışla araç Ankara güzergâhına girmektedir. Malkoçoğlu mahallelerindeki yeni yapılarda asansörlü bina oranının artmasıyla yükleme süresi kısalmaktadır.",
        [("sultangazi", ServisTipi.Sehirlerarasi)] = "Sultangazi, Arnavutköy ve Eyüpsultan akslarıyla TEM'e bağlantı kuran kuzey İstanbul ilçelerinden biridir. Sabah 06:30 yüklemesiyle araç trafik yoğunlaşmadan önce İstanbul'u terk etmekte; aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Sultangazi'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("sultangazi", ServisTipi.EvdenEve)]      = "Sultançiftliği ve Cebeci mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nEski konut stokunda asansör yoksa kat başına ekip planlaması yapılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("sultangazi", ServisTipi.Ofis)]          = "Sultangazi'deki işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("sultangazi", ServisTipi.Fuar)]          = "Sultangazi'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Arnavutköy–TEM güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("sultangazi", ServisTipi.Kamyon)]        = "Sultangazi'deki büyük 3+1 ve 4+1 dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, TEM'e yakın güzergâh avantajıyla verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e Arnavutköy aksından bağlanılmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("sultangazi", ServisTipi.Parsiyel)]      = "Sultangazi'den Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("sultangazi", ServisTipi.Ambar)]         = "Sultangazi'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── KAĞITHANe ──
        [("kagithane", ServisTipi.Kamyonet)]      = "Çağlayan ve Gültepe'nin kentsel dönüşümle yenilenen konut bloklarında 3,5 ton kamyonetimiz asansör koordinasyonuyla verimli yükleme tamamlamaktadır. Seyrantepe aksındaki modern iş ve konut yapılarında ise geniş bina girişleri büyük araçların da sorunsuz çalışmasına imkân tanımaktadır.\n\nTEM'e Maslak aksından ya da Gaziosmanpaşa üzerinden ulaşılmakta; sabah 06:30 kalkışla araç Ankara güzergâhına girmektedir. Hamidiye ve Ortabayır'daki eski konut stokunda kamyonet boyutu dar sokaklarda avantaj sağlamaktadır.",
        [("kagithane", ServisTipi.Sehirlerarasi)] = "Kağıthane, Maslak aksıyla TEM'e hızla bağlantı kuran ve son yıllarda değer kazanan İstanbul merkezi ilçelerinden biridir. Sabah 06:30 yüklemesiyle araç Maslak–TEM bağlantısından Ankara güzergâhına girmekte; aynı gün teslimat tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Kağıthane'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("kagithane", ServisTipi.EvdenEve)]      = "Hamidiye ve Ortabayır mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nÇağlayan ve Gültepe'deki yenilenmiş yapılarda yük asansörü planlamasıyla yükleme verimli biçimde tamamlanmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("kagithane", ServisTipi.Ofis)]          = "Kağıthane'deki ofis ve iş merkezlerinden Ankara'ya kurumsal taşımalarda IT ekipmanı anti-statik ambalajla güvenli biçimde paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("kagithane", ServisTipi.Fuar)]          = "Kağıthane'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Maslak–TEM güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("kagithane", ServisTipi.Kamyon)]        = "Kağıthane'deki 3+1 ve büyük dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, Maslak–TEM güzergâhından verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e Maslak aksından bağlanılmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("kagithane", ServisTipi.Parsiyel)]      = "Kağıthane'den Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("kagithane", ServisTipi.Ambar)]         = "Kağıthane'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── BEYOĞLU ──
        [("beyoglu", ServisTipi.Kamyonet)]      = "Taksim ve Cihangir'in eğimli taş döşeli sokaklarında büyük kamyon erişimi hem fiziksel hem trafiksel kısıtlar nedeniyle güçleşmekte; 3,5 ton kamyonetimiz bu bölgede standart çözüm olmaktadır. Bina girişine en yakın noktaya konumlanan araçla hızlı yükleme gerçekleştirilmekte; sabah 06:30 öncesi ya da gece geç saatlerde yükleme yoğun araç trafiğini en aza indirmektedir.\n\nGalata ve Karaköy'deki bazı modern dönüşüm yapılarında ise asansör planlamasıyla yükleme verimli biçimde tamamlanmaktadır. Maslak veya Şişli aksından TEM'e bağlantı kurulmakta; sabah erken çıkışla Ankara güzergâhına girilmektedir.",
        [("beyoglu", ServisTipi.Sehirlerarasi)] = "Beyoğlu'ndan şehirlerarası araçlar Maslak veya Şişli aksıyla TEM'e yönlendirilerek turist ve mesai trafiği yoğunlaşmadan İstanbul geride bırakılmaktadır. Sabah 06:00–06:30 arası kalkışla aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Beyoğlu'ndan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("beyoglu", ServisTipi.EvdenEve)]      = "Galata ve Karaköy'deki asansörsüz tarihi yapılarda büyük mobilyalar söküm-montaj ekibi tarafından parçalara ayrılarak merdivenden taşınmakta; battaniye ve balonlu naylon ambalajla her parça korunmaktadır. Pera ve Çukurcuma'daki dönüşüm konutlarında ise asansör koordinasyonuyla yükleme verimli biçimde tamamlanmaktadır.\n\nHar eşya taşıma öncesinde envanter listesiyle fotoğraflanmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("beyoglu", ServisTipi.Ofis)]          = "Beyoğlu'ndaki kreatif, medya ve teknoloji firmalarının Ankara'ya ofis taşımalarında gece ya da hafta sonu nakliyat tercih edilmekte; pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir. IT ekipmanı anti-statik ambalaj, arşiv belgeleri ise kilitli kolilere konulmaktadır.\n\nArşiv teslimatta imzalı tutanakla yapılmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("beyoglu", ServisTipi.Fuar)]          = "Beyoğlu'ndaki reklam, medya ve etkinlik firmalarının Ankara fuar alanlarına taşınan stand sistemleri, display paneller ve promosyon materyalleri darbe emici ambalajlarla korunmaktadır. Maslak–TEM güzergâhı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("beyoglu", ServisTipi.Kamyon)]        = "Harbiye ve Nişantaşı aksındaki büyük dairelerden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, sabah 06:00 gibi yükleme başlatılarak Şişli–TEM güzergâhından yürütülmektedir. Değerli mobilya ve antikalar için özel köpük kesim ambalaj uygulanmakta; sigorta kapsamı yükleme başlamadan aktive edilmektedir.\n\nTüm eşyalar hareket öncesinde envanter fotoğrafıyla belgelenmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("beyoglu", ServisTipi.Parsiyel)]      = "Beyoğlu'ndan Ankara'ya birkaç parça mobilya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("beyoglu", ServisTipi.Ambar)]         = "Beyoğlu'ndaki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler eşyalarını güvenli, kilitli depomuzda muhafaza edebilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── FATİH ──
        [("fatih", ServisTipi.Kamyonet)]      = "Aksaray ve Samatya'nın tarihi dar sokaklarında 3,5 ton kamyonetimiz büyük araçların erişemediği bölgelere ulaşmaktadır; trafik kısıtlamaları ve araç giriş saatleri gözetilerek yükleme planı yapılmaktadır. Kocamustafapaşa'nın bazı iç sokaklarında sabah 07:00 öncesi yükleme, trafik baskısını azaltmaktadır.\n\nYedikule ve Balat'taki kentsel dönüşüm projelerinde yeni yapıların geniş bina girişleri yüklemeyi kolaylaştırmaktadır. TEM bağlantısı Zeytinburnu veya Bayrampaşa aksından kurulmakta; Ankara güzergâhına sabah erken saatte girilmektedir.",
        [("fatih", ServisTipi.Sehirlerarasi)] = "Fatih tarihi yarımadanın kalbi olarak trafik düzenleme ve araç giriş kısıtlarına tabi olduğundan şehirlerarası araçlar bu kısıtlamaların geçerli olmadığı erken saatlerde yüklemelerini tamamlamaktadır. Zeytinburnu veya Bayrampaşa aksından TEM'e bağlantı sağlanmakta; aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Fatih'ten Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("fatih", ServisTipi.EvdenEve)]      = "Kocamustafapaşa ve Balat'taki asansörsüz tarihi apartmanlarda büyük mobilyalar söküm-montaj ekibi tarafından parçalara ayrılarak merdivenden taşınmakta; her parça battaniye ve balonlu naylon ambalajla korunmaktadır. Kentsel dönüşüm alanlarındaki yeni yapılarda ise asansör koordinasyonuyla yükleme verimli biçimde tamamlanmaktadır.\n\nHer eşya taşıma öncesinde envanter listesiyle fotoğraflanmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("fatih", ServisTipi.Ofis)]          = "Fatih'teki ticari ve küçük ölçekli ofislerin Ankara'ya taşımalarında IT ekipmanı anti-statik ambalajla güvenle paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Araç giriş kısıtları nedeniyle yükleme saati önceden ayarlanmaktadır.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır. Arşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir.",
        [("fatih", ServisTipi.Fuar)]          = "Fatih'teki firmalar için Ankara fuar taşımalarında tarihi yarımadanın araç giriş kısıtlamaları gözetilerek sabah erken kalkış planlanmakta; stand ve ekipmanlar darbe emici ambalajlarla hazırlanmaktadır. Fuar açılışından 2 gün önce teslimat taahhüt edilmektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("fatih", ServisTipi.Kamyon)]        = "Fatih'teki büyük konutlarda kamyon erişimi cadde bazlı değerlendirilmekte; ana arterlere yakın adreslerde uygun saatlerle kamyon doğrudan yükleme yapabilmekte, uzak iç sokaklarda önce kamyonete aktarım gerekebilmektedir. Bu kombinasyon önceden planlanmakta ve müşteriye bildirilmektedir.\n\nTüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("fatih", ServisTipi.Parsiyel)]      = "Fatih'ten Ankara'ya birkaç parça eşya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("fatih", ServisTipi.Ambar)]         = "Fatih'teki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler eşyalarını güvenli, kilitli depomuzda muhafaza edebilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── EYÜPSULTAN ──
        [("eyupsultan", ServisTipi.Kamyonet)]      = "Alibeyköy'ün yoğun konut mahallelerinde dar sokaklara uyum sağlayan 3,5 ton kamyonetimiz bina önüne en yakın konuma kolayca yerleşmekte; Nişanca'daki tarihi mahalle dokusunda da bu araç boyutu standart tercih olmaktadır. Göktürk'ün geniş villa bölgelerinde ise büyük araç yolları hem kamyon hem kamyonet erişimine elverişlidir.\n\nTEM'e Arnavutköy aksından bağlantı sağlanmakta; sabah 06:30 kalkışla araç Ankara güzergâhına girmektedir. Göktürk'ten çıkış Arnavutköy çevreyoluyla TEM'e hızla bağlanmaktadır.",
        [("eyupsultan", ServisTipi.Sehirlerarasi)] = "Eyüpsultan, Arnavutköy aksıyla TEM'e kısa sürede bağlanabilen kuzey Avrupa yakası ilçelerinden biridir. Sabah 06:30 yüklemesiyle araç trafik yoğunlaşmadan önce İstanbul'u terk etmekte; aynı gün Ankara teslimatı tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Eyüpsultan'dan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("eyupsultan", ServisTipi.EvdenEve)]      = "Göktürk'teki villa ve müstakil konutlardan Ankara'ya değerli mobilya ve büyük ev eşyalarının taşınmasında özel köpük kesim ambalaj ve battaniye sarma uygulanmakta; ekip söküm-montaj konusunda deneyimlidir. Alibeyköy'deki çok katlı yapılarda ise asansör ön rezervasyonu ve komşu koordinasyonuyla kapsamlı ev taşıması planlanmaktadır.\n\nHer eşya taşıma öncesinde envanter listesiyle fotoğraflanmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("eyupsultan", ServisTipi.Ofis)]          = "Eyüpsultan'daki işletmelerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Göktürk'teki prestijli ofis ve iş merkezlerinden değerli ekipman taşımalarında ek sigorta teminatı önerilmektedir.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır. Arşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir.",
        [("eyupsultan", ServisTipi.Fuar)]          = "Eyüpsultan'daki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Arnavutköy–TEM güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("eyupsultan", ServisTipi.Kamyon)]        = "Göktürk ve Nişanca'daki büyük villa ile müstakil konutlardan Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik sigortalı taşıma yapılmaktadır. Göktürk'ün geniş araç yolları kamyon yüklemesini kolaylaştırmakta; değerli mobilyalar için özel ambalaj uygulanmaktadır.\n\nTüm eşyalar hareket öncesinde envanter fotoğrafıyla belgelenmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("eyupsultan", ServisTipi.Parsiyel)]      = "Eyüpsultan'dan Ankara'ya az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("eyupsultan", ServisTipi.Ambar)]         = "Eyüpsultan'daki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── SARIYER ──
        [("sariyer", ServisTipi.Kamyonet)]      = "Yeniköy ve Tarabya'nın Boğaz kıyısındaki köklü sokaklarında büyük araç geçişi hem fiziksel hem trafik kısıtlar nedeniyle güçleşmekte; 3,5 ton kamyonetimiz bina girişine en yakın noktaya kolayca konumlanarak yalı ve köşklere ulaşım sağlamaktadır. Gerektiğinde ön taşımayla eşyalar geniş artere aktarılmaktadır.\n\nİstinye ve Büyükdere caddesindeki modern yapılarda ise yük asansörü planlamasıyla yükleme verimli biçimde tamamlanmaktadır. TEM'e Maslak aksından ulaşılmakta; sabah erken çıkışla Boğaz yoğunluğu aşılmaktadır.",
        [("sariyer", ServisTipi.Sehirlerarasi)] = "Sarıyer, Maslak aksıyla TEM'e bağlantı kurabilen kuzey Boğaz ilçelerinden biri olarak şehirlerarası araçların sabah erken kalkışla Boğaz trafiğini atlayabildiği bir noktadır. Sabah 06:00–06:30 yüklemesiyle araç Maslak–TEM bağlantısından Ankara güzergâhına girmekte; aynı gün teslimat tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Sarıyer'den Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("sariyer", ServisTipi.EvdenEve)]      = "İstinye ve Büyükdere'deki modern konut yapılarında asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nYeniköy ve Tarabya'daki tarihi konutlarda asansör olmadığında kat başına ekip planlaması yapılmakta; büyük mobilyalar merdivenden güvenle çıkarılmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("sariyer", ServisTipi.Ofis)]          = "Sarıyer'deki iş yerleri ve Maslak aksındaki ofislerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla güvenle paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("sariyer", ServisTipi.Fuar)]          = "Sarıyer'deki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. Maslak–TEM güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("sariyer", ServisTipi.Kamyon)]        = "Zekeriyaköy ve İstinye'deki büyük villa ve konutlardan Ankara'ya değerli mobilya ile villa eşyaları 12–18 ton kapalı kasalı kamyon ile tek seferlik sigortalı taşınmaktadır. Geniş araç yolları sayesinde Zekeriyaköy'de kamyon doğrudan yükleme yapabilmektedir.\n\nTüm eşyalar hareket öncesinde envanter fotoğrafıyla belgelenmekte; değerli parçalar için özel köpük kesim ambalaj uygulanmaktadır. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("sariyer", ServisTipi.Parsiyel)]      = "Sarıyer'den Ankara'ya birkaç parça eşya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("sariyer", ServisTipi.Ambar)]         = "Sarıyer'deki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler eşyalarını güvenli, kilitli depomuzda muhafaza edebilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── ZEYTİNBURNU ──
        [("zeytinburnu", ServisTipi.Kamyonet)]      = "Merkezefendi ve Seyitnizam'daki konut bloklarında 3,5 ton kamyonetimiz asansör koordinasyonuyla verimli yükleme tamamlamaktadır. Kazlıçeşme'nin kısmen dar sanayi sokaklarında kamyonet boyutu manevra avantajı sağlamakta; geniş sanayi arterlerine yakın adreslerde ise kamyon erişimi sorunsuz mümkündür.\n\nE-5 üzerindeki konumuyla ilçe Ankara güzergâhına doğrudan bağlantı sunmakta; sabah 06:30 yüklemesiyle trafiksiz çıkış sağlanmaktadır. Nuripaşa'daki eski konut stokunda asansör yoksa kat başına ekip planlaması yapılmaktadır.",
        [("zeytinburnu", ServisTipi.Sehirlerarasi)] = "Zeytinburnu, E-5 üzerindeki konumuyla Ankara güzergâhına en doğrudan bağlantı sunan Avrupa yakası ilçelerinden biridir. Sabah 06:30 yüklemesiyle araç E-5'ten TEM'e aktarımla Ankara yoluna girmekte; aynı gün teslimat standart olarak tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Zeytinburnu'ndan Ankara'nın tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sağlanmaktadır.",
        [("zeytinburnu", ServisTipi.EvdenEve)]      = "Veliefendi ve Nuripaşa mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nMerkezefendi'deki yeni yapılarda yük asansörü planlamasıyla yükleme verimli biçimde tamamlanmaktadır. Ankara'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("zeytinburnu", ServisTipi.Ofis)]          = "Zeytinburnu'ndaki sanayi işletmeleri ve ticari ofislerin Ankara'ya kurumsal taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("zeytinburnu", ServisTipi.Fuar)]          = "Zeytinburnu'ndaki firmalar için Ankara fuar alanlarına taşınan stand sistemleri ve tanıtım gereçleri darbe emici ambalajlarla hazırlanmaktadır. E-5 güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("zeytinburnu", ServisTipi.Kamyon)]        = "Zeytinburnu'ndaki büyük konut ve sanayi işletmelerinden Ankara'ya 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, E-5'in sağladığı direkt güzergâh avantajıyla verimli yürütülmektedir. Geniş sanayi arterleri kamyon yüklemesini kolaylaştırmakta; tüm eşyalar envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak E-5'ten TEM'e aktarımla Ankara yoluna girilmektedir. Ankara'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("zeytinburnu", ServisTipi.Parsiyel)]      = "Zeytinburnu'ndan Ankara'ya birkaç parça mobilya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden Ankara teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("zeytinburnu", ServisTipi.Ambar)]         = "Zeytinburnu'ndaki konutunu boşaltıp Ankara'ya geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli, kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar Ankara adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",
    };
